"""
Parameterized generator for GH849_marshmallow_293.

Source PR:    https://github.com/marshmallow-code/marshmallow/pull/293
Source Issue: https://github.com/marshmallow-code/marshmallow/issues/290

Seed varies: renames 'accepted' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH849_marshmallow_293'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH849_marshmallow_293'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accepted', 'accepted' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH849_marshmallow_293',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'marshmallow-code/marshmallow',
                "pr_number": 293,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/marshmallow-code/marshmallow/pull/293",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'docs/quickstart.rst': '.. _quickstart:\n.. module:: marshmallow\n\nQuickstart\n==========\n\nThis guide will walk you through the basics of creating schemas for serializing and deserializing data.\n\nDeclaring Schemas\n-----------------\n\nLet\'s start with a basic user "model".\n\n.. code-block:: python\n\n    import datetime as dt\n\n    class User(object):\n        def __init__(self, name, email):\n            self.name = name\n            self.email = email\n            self.created_at = dt.datetime.now()\n\n        def __repr__(self):\n            return \'<User(name={self.name!r})>\'.format(self=self)\n\n\nCreate a schema by defining a class with variables mapping attribute names to :class:`Field <fields.Field>` objects.\n\n.. code-block:: python\n\n    from marshmallow import Schema, fields\n\n    class UserSchema(Schema):\n        name = fields.Str()\n        email = fields.Email()\n        created_at = fields.DateTime()\n\n.. seealso::\n\n    For a full reference on the available field classes, see the :ref:`API Docs <api_fields>`.\n\n\nSerializing Objects ("Dumping")\n-------------------------------\n\nSerialize objects by passing them to your schema\'s :meth:`dump <marshmallow.Schema.dump>` method, which returns the formatted result (as well as a dictionary of validation errors, which we\'ll :ref:`revisit later <validation>`).\n\n.. code-block:: python\n\n    from marshmallow import pprint\n\n    user = User(name="Monty", email="monty@python.org")\n    schema = UserSchema()\n    result = schema.dump(user)\n    pprint(result.data)\n    # {"name": "Monty",\n    #  "email": "monty@python.org",\n    #  "created_at": "2014-08-17T14:54:16.049594+00:00"}\n\nYou can also serialize to a JSON-encoded string using :meth:`dumps <marshmallow.Schema.dumps>`.\n\n.. code-block:: python\n\n    json_result = schema.dumps(user)\n    pprint(json_result.data)\n    # \'{"name": "Monty", "email": "monty@python.org", "created_at": "2014-08-17T14:54:16.049594+00:00"}\'\n\nFiltering output\n++++++++++++++++\n\nYou may not need to output all declared fields every time you use a schema. You can specify which fields to output with the ``only`` parameter.\n\n.. code-block:: python\n\n    summary_schema = UserSchema(only=(\'name\', \'email\'))\n    summary_schema.dump(user).data\n    # {"name": "Monty Python", "email": "monty@python.org"}\n\nYou can also exclude fields by passing in the ``exclude`` parameter.\n\n\nDeserializing Objects ("Loading")\n---------------------------------\n\nThe opposite of the :meth:`dump <Schema.dump>` method is the :meth:`load <Schema.load>` method, which deserializes an input dictionary to an application-level data structure.\n\nBy default, :meth:`load <Schema.load>` will return a dictionary of field names mapped to the deserialized values.\n\n.. code-block:: python\n\n    from pprint import pprint\n\n    user_data = {\n        \'created_at\': \'2014-08-11T05:26:03.869245\',\n        \'email\': u\'ken@yahoo.com\',\n        \'name\': u\'Ken\'\n    }\n    schema = UserSchema()\n    result = schema.load(user_data)\n    pprint(result.data)\n    # {\'name\': \'Ken\',\n    #  \'email\': \'ken@yahoo.com\',\n    #  \'created_at\': datetime.datetime(2014, 8, 11, 5, 26, 3, 869245)},\n\nNotice that the datetime string was converted to a `datetime` object.\n\nDeserializing to Objects\n++++++++++++++++++++++++\n\nIn order to deserialize to an object, define a method of your :class:`Schema` and decorate it with `post_load <marshmallow.decorators.post_load>`. The method receives a dictionary of deserialized data as its only parameter.\n\n.. code-block:: python\n    :emphasize-lines: 8-10\n\n    from marshmallow import Schema, fields, post_load\n\n    class UserSchema(Schema):\n        name = fields.Str()\n        email = fields.Email()\n        created_at = fields.DateTime()\n\n        @post_load\n        def make_user(self, data):\n            return User(**data)\n\nNow, the :meth:`load <Schema.load>` method will return a ``User`` object.\n\n.. code-block:: python\n\n    user_data = {\n        \'name\': \'Ronnie\',\n        \'email\': \'ronnie@stones.com\'\n    }\n    schema = UserSchema()\n    result = schema.load(user_data)\n    result.data  # => <User(name=\'Ronnie\')>\n\nHandling Collections of Objects\n-------------------------------\n\nIterable collections of objects are also serializable and deserializable. Just set ``many=True``.\n\n.. code-block:: python\n    :emphasize-lines: 3,4\n\n    user1 = User(name="Mick", email="mick@stones.com")\n    user2 = User(name="Keith", email="keith@stones.com")\n    users = [user1, user2]\n    schema = UserSchema(many=True)\n    result = schema.dump(users)  # OR UserSchema().dump(users, many=True)\n    result.data\n    # [{\'name\': u\'Mick\',\n    #   \'email\': u\'mick@stones.com\',\n    #   \'created_at\': \'2014-08-17T14:58:57.600623+00:00\'}\n    #  {\'name\': u\'Keith\',\n    #   \'email\': u\'keith@stones.com\',\n    #   \'created_at\': \'2014-08-17T14:58:57.600623+00:00\'}]\n\n\n.. _validation:\n\nValidation\n----------\n\n:meth:`Schema.load` (and its JSON-decoding counterpart, :meth:`Schema.loads`) returns a dictionary of validation errors as the second element of its return value. Some fields, such as the :class:`Email <fields.Email>` and :class:`URL <fields.URL>` fields, have built-in validation.\n\n.. code-block:: python\n\n    data, errors = UserSchema().load({\'email\': \'foo\'})\n    errors  # => {\'email\': [\'"foo" is not a valid email address.\']}\n    # OR, equivalently\n    result = UserSchema().load({\'email\': \'foo\'})\n    result.errors  # => {\'email\': [\'"foo" is not a valid email address.\']}\n\n\nWhen validating a collection, the errors dictionary will be keyed on the indicies of invalid items.\n\n.. code-block:: python\n\n    class BandMemberSchema(Schema):\n        name = fields.String(required=True)\n        email = fields.Email()\n\n    user_data = [\n        {\'email\': \'mick@stones.com\', \'name\': \'Mick\'},\n        {\'email\': \'invalid\', \'name\': \'Invalid\'},  # invalid email\n        {\'email\': \'keith@stones.com\', \'name\': \'Keith\'},\n        {\'email\': \'charlie@stones.com\'},  # missing "name"\n    ]\n\n    result = BandMemberSchema(many=True).load(user_data)\n    result.errors\n    # {1: {\'email\': [\'"invalid" is not a valid email address.\']},\n    #  3: {\'name\': [\'Missing data for required field.\']}}\n\nYou can perform additional validation for a field by passing it a ``validate`` callable (function, lambda, or object with ``__call__`` defined).\n\n.. code-block:: python\n    :emphasize-lines: 4\n\n    class ValidatedUserSchema(UserSchema):\n        # NOTE: This is a contrived example.\n        # You could use marshmallow.validate.Range instead of an anonymous function here\n        age = fields.Number(validate=lambda n: 18 <= n <= 40)\n\n    in_data = {\'name\': \'Mick\', \'email\': \'mick@stones.com\', \'age\': 71}\n    result = ValidatedUserSchema().load(in_data)\n    result.errors  # => {\'age\': [\'Validator <lambda>(71.0) is False\']}\n\n\nValidation functions either return a boolean or raise a :exc:`ValidationError`. If a :exc:`ValidationError <marshmallow.exceptions.ValidationError>` is raised, its message is stored when validation fails.\n\n.. code-block:: python\n    :emphasize-lines: 7,10,14\n\n    from marshmallow import Schema, fields, ValidationError\n\n    def validate_quantity(n):\n        if n < 0:\n            raise ValidationError(\'Quantity must be greater than 0.\')\n        if n > 30:\n            raise ValidationError(\'Quantity must not be greater than 30.\')\n\n    class ItemSchema(Schema):\n        quantity = fields.Integer(validate=validate_quantity)\n\n    in_data = {\'quantity\': 31}\n    result, errors = ItemSchema().load(in_data)\n    errors  # => {\'quantity\': [\'Quantity must not be greater than 30.\']}\n\n.. note::\n\n    If you have multiple validations to perform, you may also pass a collection (list, tuple, generator) of callables.\n\n.. note::\n\n    :meth:`Schema.dump` also returns a dictionary of errors, which will include any ``ValidationErrors`` raised during serialization. However, the ``required``, ``allow_none``, and ``validate`` parameters only apply during deserialization.\n\n\nField Validators as Methods\n+++++++++++++++++++++++++++\n\nIt is often convenient to write validators as methods. Use the `validates <marshmallow.decorators.validates>` decorator to register field validator methods.\n\n.. code-block:: python\n\n    from marshmallow import fields, Schema, validates\n\n    class ItemSchema(Schema):\n        quantity = fields.Integer()\n\n        @validates(\'quantity\')\n        def validate_quantity(self, value):\n            if n < 0:\n                raise ValidationError(\'Quantity must be greater than 0.\')\n            if n > 30:\n                raise ValidationError(\'Quantity must not be greater than 30.\')\n\n\n``strict`` Mode\n+++++++++++++++\n\n    If you set ``strict=True`` in either the Schema constructor or as a ``class Meta`` option, an error will be raised when invalid data are passed in. You can access the dictionary of validation errors from the `ValidationError.messages <marshmallow.exceptions.ValidationError.messages>` attribute.\n\n    .. code-block:: python\n\n        from marshmallow import ValidationError\n\n        try:\n            UserSchema(strict=True).load({\'email\': \'foo\'})\n        except ValidationError as err:\n            print(err.messages)# => {\'email\': [\'"foo" is not a valid email address.\']}\n\n.. seealso::\n\n    You can register a custom error handler function for a schema by overriding the :func:`handle_error <Schema.handle_error>` method. See the :ref:`Extending Schemas <extending>` page for more info.\n\n.. seealso::\n\n    Need schema-level validation? See the :ref:`Extending Schemas <schemavalidation>` page.\n\nRequired Fields\n+++++++++++++++\n\nYou can make a field required by passing ``required=True``. An error will be stored if the the value is missing from the input to :meth:`Schema.load`.\n\nAlternatively, you can provide a custom error message by passing ``required=\'My custom message\'``.\nDictionaries or lists are also accepted as the custom error message, in case you want to provide more information with the error.\n\n.. code-block:: python\n    :emphasize-lines: 2,3,4\n\n    class UserSchema(Schema):\n        name = fields.String(required=True)\n        age = fields.Integer(required=\'Age is required.\')\n        city = fields.String(required={\'message\': \'City required\', \'code\': 400})\n        email = fields.Email()\n\n    data, errors = UserSchema().load({\'email\': \'foo@bar.com\'})\n    errors\n    # {\'name\': [\'Missing data for required field.\'],\n    #  \'age\': [\'Age is required.\'],\n    #  \'city\': {\'message\': \'City required\', \'code\': 400}}\n\nSchema.validate\n+++++++++++++++\n\nIf you only need to validate input data (without deserializing to an object), you can use :meth:`Schema.validate`.\n\n.. code-block:: python\n\n    errors = UserSchema().validate({\'name\': \'Ronnie\', \'email\': \'invalid-email\'})\n    errors  # {\'email\': [\'"invalid-email" is not a valid email address.\']}\n\n\nSpecifying Attribute Names\n--------------------------\n\nBy default, `Schemas` will marshal the object attributes that are identical to the schema\'s field names. However, you may want to have different field and attribute names. In this case, you can explicitly specify which attribute names to use.\n\n.. code-block:: python\n    :emphasize-lines: 3,4,11,12\n\n    class UserSchema(Schema):\n        name = fields.String()\n        email_addr = fields.String(attribute="email")\n        date_created = fields.DateTime(attribute="created_at")\n\n    user = User(\'Keith\', email=\'keith@stones.com\')\n    ser = UserSchema()\n    result, errors = ser.dump(user)\n    pprint(result)\n    # {\'name\': \'Keith\',\n    #  \'email_addr\': \'keith@stones.com\',\n    #  \'date_created\': \'2014-08-17T14:58:57.600623+00:00\'}\n\n\nSpecifying Deserialization Keys\n-------------------------------\n\nBy default `Schemas` will unmarshal an input dictionary to an output dictionary whose keys are identical to the field names.  However, if you are consuming data that does not exactly match your schema, you can specify additional keys to load values by passing the `load_from` argument.\n\n.. code-block:: python\n    :emphasize-lines: 2,3,11,12\n\n    class UserSchema(Schema):\n        name = fields.String()\n        email = fields.Email(load_from=\'emailAddress\')\n\n    data = {\n        \'name\': \'Mike\',\n        \'emailAddress\': \'foo@bar.com\'\n    }\n    s = UserSchema()\n    result, errors = s.load(data)\n    #{\'name\': u\'Mike\',\n    # \'email\': \'foo@bar.com\'}\n\n.. _meta_options:\n\nRefactoring: Implicit Field Creation\n------------------------------------\n\nWhen your model has many attributes, specifying the field type for every attribute can get repetitive, especially when many of the attributes are already native Python datatypes.\n\nThe *class Meta* paradigm allows you to specify which attributes you want to serialize. Marshmallow will choose an appropriate field type based on the attribute\'s type.\n\nLet\'s refactor our User schema to be more concise.\n\n.. code-block:: python\n    :emphasize-lines: 4,5\n\n    # Refactored schema\n    class UserSchema(Schema):\n        uppername = fields.Function(lambda obj: obj.name.upper())\n        class Meta:\n            fields = ("name", "email", "created_at", "uppername")\n\nNote that ``name`` will be automatically formatted as a :class:`String <marshmallow.fields.String>` and ``created_at`` will be formatted as a :class:`DateTime <marshmallow.fields.DateTime>`.\n\n.. note::\n\n    If instead you want to specify which field names to include *in addition* to the explicitly declared fields, you can use the ``additional`` option.\n\n    The schema below is equivalent to above:\n\n    .. code-block:: python\n\n        class UserSchema(Schema):\n            uppername = fields.Function(lambda obj: obj.name.upper())\n            class Meta:\n                # No need to include \'uppername\'\n                additional = ("name", "email", "created_at")\n\nOrdering Output\n---------------\n\nFor some use cases, it may be useful to maintain field ordering of serialized output. To enable ordering, set the ``ordered`` option to `True`. This will instruct marshmallow to serialize data to a `collections.OrderedDict`.\n\n.. code-block:: python\n    :emphasize-lines: 7\n\n    from collections import OrderedDict\n\n    class UserSchema(Schema):\n        uppername = fields.Function(lambda obj: obj.name.upper())\n        class Meta:\n            fields = ("name", "email", "created_at", "uppername")\n            ordered = True\n\n    u = User(\'Charlie\', \'charlie@stones.com\')\n    schema = UserSchema()\n    result = schema.dump(u)\n    assert isinstance(result.data, OrderedDict)\n    # marshmallow\'s pprint function maintains order\n    pprint(result.data, indent=2)\n    # {\n    #   "name": "Charlie",\n    #   "email": "charlie@stones.com",\n    #   "created_at": "2014-10-30T08:27:48.515735+00:00",\n    #   "uppername": "CHARLIE"\n    # }\n\n\n"Read-only" and "Write-only" Fields\n-----------------------------------\n\nIn the context of a web API, the ``dump_only`` and ``load_only`` parameters are conceptually equivalent to "read-only" and "write-only" fields, respectively.\n\n.. code-block:: python\n\n    class UserSchema(Schema):\n        name = fields.Str()\n        # password is "write-only"\n        password = fields.Str(load_only=True)\n        # created_at is "read-only"\n        created_at = fields.DateTime(dump_only=True)\n\n\nNext Steps\n----------\n\n- Need to represent relationships between objects? See the :ref:`Nesting Schemas <nesting>` page.\n- Want to create your own field type? See the :ref:`Custom Fields <custom_fields>` page.\n- Need to add schema-level validation, post-processing, or error handling behavior? See the :ref:`Extending Schemas <extending>` page.\n- For example applications using marshmallow, check out the :ref:`Examples <examples>` page.\n',
            'marshmallow/marshalling.py': '# -*- coding: utf-8 -*-\n"""Utility classes and values used for marshalling and unmarshalling objects to\nand from primitive types.\n\n.. warning::\n\n    This module is treated as private API.\n    Users should not need to use this module directly.\n"""\n\nfrom __future__ import unicode_literals\n\nfrom marshmallow.utils import missing\nfrom marshmallow.compat import text_type, iteritems\nfrom marshmallow.exceptions import (\n    ValidationError,\n)\n\n__all__ = [\n    \'Marshaller\',\n    \'Unmarshaller\',\n]\n\n\nclass ErrorStore(object):\n\n    def __init__(self):\n        #: Dictionary of errors stored during serialization\n        self.errors = {}\n        #: List of `Field` objects which have validation errors\n        self.error_fields = []\n        #: List of field_names which have validation errors\n        self.error_field_names = []\n        #: True while (de)serializing a collection\n        self._pending = False\n\n    def reset_errors(self):\n        self.errors = {}\n        self.error_field_names = []\n        self.error_fields = []\n\n    def get_errors(self, index=None):\n        if index is not None:\n            errors = self.errors.get(index, {})\n            self.errors[index] = errors\n        else:\n            errors = self.errors\n        return errors\n\n    def call_and_store(self, getter_func, data, field_name, field_obj, index=None):\n        """Call ``getter_func`` with ``data`` as its argument, and store any `ValidationErrors`.\n\n        :param callable getter_func: Function for getting the serialized/deserialized\n            value from ``data``.\n        :param data: The data passed to ``getter_func``.\n        :param str field_name: Field name.\n        :param FieldABC field_obj: Field object that performs the\n            serialization/deserialization behavior.\n        :param int index: Index of the item being validated, if validating a collection,\n            otherwise `None`.\n        """\n        try:\n            value = getter_func(data)\n        except ValidationError as err:  # Store validation errors\n            self.error_fields.append(field_obj)\n            self.error_field_names.append(field_name)\n            errors = self.get_errors(index=index)\n            # Warning: Mutation!\n            if isinstance(err.messages, dict):\n                errors[field_name] = err.messages\n            else:\n                errors.setdefault(field_name, []).extend(err.messages)\n            # When a Nested field fails validation, the marshalled data is stored\n            # on the ValidationError\'s data attribute\n            value = err.data or missing\n        return value\n\nclass Marshaller(ErrorStore):\n    """Callable class responsible for serializing data and storing errors.\n\n    :param str prefix: Optional prefix that will be prepended to all the\n        serialized field names.\n    """\n    def __init__(self, prefix=\'\'):\n        self.prefix = prefix\n        ErrorStore.__init__(self)\n\n    def serialize(self, obj, fields_dict, many=False,\n                  accessor=None, dict_class=dict, index_errors=True, index=None):\n        """Takes raw data (a dict, list, or other object) and a dict of\n        fields to output and serializes the data based on those fields.\n\n        :param obj: The actual object(s) from which the fields are taken from\n        :param dict fields_dict: Mapping of field names to :class:`Field` objects.\n        :param bool many: Set to `True` if ``data`` should be serialized as\n            a collection.\n        :param callable accessor: Function to use for getting values from ``obj``.\n        :param type dict_class: Dictionary class used to construct the output.\n        :param bool index_errors: Whether to store the index of invalid items in\n            ``self.errors`` when ``many=True``.\n        :param int index: Index of the item being serialized (for storing errors) if\n            serializing a collection, otherwise `None`.\n        :return: A dictionary of the marshalled data\n\n        .. versionchanged:: 1.0.0\n            Renamed from ``marshal``.\n        """\n        # Reset errors dict if not serializing a collection\n        if not self._pending:\n            self.reset_errors()\n        if many and obj is not None:\n            self._pending = True\n            ret = [self.serialize(d, fields_dict, many=False,\n                                    dict_class=dict_class, accessor=accessor,\n                                    index=idx, index_errors=index_errors)\n                    for idx, d in enumerate(obj)]\n            self._pending = False\n            if self.errors:\n                raise ValidationError(\n                    self.errors,\n                    field_names=self.error_field_names,\n                    fields=self.error_fields,\n                    data=ret,\n                )\n            return ret\n        items = []\n        for attr_name, field_obj in iteritems(fields_dict):\n            if getattr(field_obj, \'load_only\', False):\n                continue\n            if not self.prefix:\n                key = attr_name\n            else:\n                key = \'\'.join([self.prefix, attr_name])\n            getter = lambda d: field_obj.serialize(attr_name, d, accessor=accessor)\n            value = self.call_and_store(\n                getter_func=getter,\n                data=obj,\n                field_name=key,\n                field_obj=field_obj,\n                index=(index if index_errors else None)\n            )\n            if value is missing:\n                continue\n            items.append((key, value))\n        ret = dict_class(items)\n        if self.errors and not self._pending:\n            raise ValidationError(\n                self.errors,\n                field_names=self.error_field_names,\n                fields=self.error_fields,\n                data=ret\n            )\n        return ret\n\n    # Make an instance callable\n    __call__ = serialize\n\n# Key used for schema-level validation errors\nSCHEMA = \'_schema\'\n\nclass Unmarshaller(ErrorStore):\n    """Callable class responsible for deserializing data and storing errors.\n\n    .. versionadded:: 1.0.0\n    """\n\n    default_schema_validation_error = \'Invalid data.\'\n\n    def run_validator(self, validator_func, output,\n            original_data, fields_dict, index=None,\n            many=False, pass_original=False):\n        try:\n            if pass_original:  # Pass original, raw data (before unmarshalling)\n                res = validator_func(output, original_data)\n            else:\n                res = validator_func(output)\n            if res is False:\n                raise ValidationError(self.default_schema_validation_error)\n        except ValidationError as err:\n            errors = self.get_errors(index=index)\n            # Store or reraise errors\n            if err.field_names:\n                field_names = err.field_names\n                field_objs = [fields_dict[each] if each in fields_dict else None\n                              for each in field_names]\n            else:\n                field_names = [SCHEMA]\n                field_objs = []\n            self.error_field_names = field_names\n            self.error_fields = field_objs\n            for field_name in field_names:\n                if isinstance(err.messages, (list, tuple)):\n                    # self.errors[field_name] may be a dict if schemas are nested\n                    if isinstance(errors.get(field_name), dict):\n                        errors[field_name].setdefault(\n                            SCHEMA, []\n                        ).extend(err.messages)\n                    else:\n                        errors.setdefault(field_name, []).extend(err.messages)\n                elif isinstance(err.messages, dict):\n                    errors.setdefault(field_name, []).append(err.messages)\n                else:\n                    errors.setdefault(field_name, []).append(text_type(err))\n            raise ValidationError(\n                self.errors,\n                fields=field_objs,\n                field_names=field_names,\n                data=output\n            )\n\n    def deserialize(self, data, fields_dict, many=False,\n            dict_class=dict, index_errors=True, index=None):\n        """Deserialize ``data`` based on the schema defined by ``fields_dict``.\n\n        :param dict data: The data to deserialize.\n        :param dict fields_dict: Mapping of field names to :class:`Field` objects.\n        :param bool many: Set to `True` if ``data`` should be deserialized as\n            a collection.\n        :param type dict_class: Dictionary class used to construct the output.\n        :param bool index_errors: Whether to store the index of invalid items in\n            ``self.errors`` when ``many=True``.\n        :param int index: Index of the item being serialized (for storing errors) if\n            serializing a collection, otherwise `None`.\n        :return: A dictionary of the deserialized data.\n        """\n        # Reset errors if not deserializing a collection\n        if not self._pending:\n            self.reset_errors()\n        if many and data is not None:\n            self._pending = True\n            ret = [self.deserialize(d, fields_dict, many=False,\n                        dict_class=dict_class,\n                        index=idx, index_errors=index_errors)\n                    for idx, d in enumerate(data)]\n\n            self._pending = False\n            if self.errors:\n                raise ValidationError(\n                    self.errors,\n                    field_names=self.error_field_names,\n                    fields=self.error_fields,\n                    data=ret,\n                )\n            return ret\n        if data is not None:\n            items = []\n            for attr_name, field_obj in iteritems(fields_dict):\n                if field_obj.dump_only:\n                    continue\n                try:\n                    raw_value = data.get(attr_name, missing)\n                except AttributeError:  # Input data is not a dict\n                    errors = self.get_errors(index=index)\n                    msg = field_obj.error_messages[\'type\'].format(\n                        input=data, input_type=data.__class__.__name__\n                    )\n                    self.error_field_names = [SCHEMA]\n                    self.error_fields = []\n                    errors = self.get_errors()\n                    errors.setdefault(SCHEMA, []).append(msg)\n                    # Input data type is incorrect, so we can bail out early\n                    break\n                field_name = attr_name\n                if raw_value is missing and field_obj.load_from:\n                    field_name = field_obj.load_from\n                    raw_value = data.get(field_obj.load_from, missing)\n                if raw_value is missing:\n                    _miss = field_obj.missing\n                    raw_value = _miss() if callable(_miss) else _miss\n                if raw_value is missing and not field_obj.required:\n                    continue\n\n                getter = lambda val: field_obj.deserialize(\n                    val,\n                    field_obj.load_from or attr_name,\n                    data\n                )\n                value = self.call_and_store(\n                    getter_func=getter,\n                    data=raw_value,\n                    field_name=field_name,\n                    field_obj=field_obj,\n                    index=(index if index_errors else None)\n                )\n                if value is not missing:\n                    key = fields_dict[attr_name].attribute or attr_name\n                    items.append((key, value))\n            ret = dict_class(items)\n        else:\n            ret = None\n\n        if self.errors and not self._pending:\n            raise ValidationError(\n                self.errors,\n                field_names=self.error_field_names,\n                fields=self.error_fields,\n                data=ret,\n            )\n        return ret\n\n    # Make an instance callable\n    __call__ = deserialize\n',
            'marshmallow/schema.py': '# -*- coding: utf-8 -*-\n"""The :class:`Schema` class, including its metaclass and options (class Meta)."""\nfrom __future__ import absolute_import, unicode_literals\n\nfrom collections import defaultdict, Mapping\nimport copy\nimport datetime as dt\nimport decimal\nimport inspect\nimport json\nimport types\nimport uuid\nimport warnings\nfrom collections import namedtuple\nfrom functools import partial\n\nfrom marshmallow import base, fields, utils, class_registry, marshalling\nfrom marshmallow.compat import (with_metaclass, iteritems, text_type,\n                                binary_type, OrderedDict)\nfrom marshmallow.exceptions import ValidationError\nfrom marshmallow.orderedset import OrderedSet\nfrom marshmallow.decorators import (PRE_DUMP, POST_DUMP, PRE_LOAD, POST_LOAD,\n                                    VALIDATES, VALIDATES_SCHEMA)\n\n\n#: Return type of :meth:`Schema.dump` including serialized data and errors\nMarshalResult = namedtuple(\'MarshalResult\', [\'data\', \'errors\'])\n#: Return type of :meth:`Schema.load`, including deserialized data and errors\nUnmarshalResult = namedtuple(\'UnmarshalResult\', [\'data\', \'errors\'])\n\ndef _get_fields(attrs, field_class, pop=False, ordered=False):\n    """Get fields from a class. If ordered=True, fields will sorted by creation index.\n\n    :param attrs: Mapping of class attributes\n    :param type field_class: Base field class\n    :param bool pop: Remove matching fields\n    """\n    getter = getattr(attrs, \'pop\' if pop else \'get\')\n    fields = [\n        (field_name, getter(field_name))\n        for field_name, field_value in list(iteritems(attrs))\n        if utils.is_instance_or_subclass(field_value, field_class)\n    ]\n    if ordered:\n        return sorted(\n            fields,\n            key=lambda pair: pair[1]._creation_index,\n        )\n    else:\n        return fields\n\n# This function allows Schemas to inherit from non-Schema classes and ensures\n#   inheritance according to the MRO\ndef _get_fields_by_mro(klass, field_class, ordered=False):\n    """Collect fields from a class, following its method resolution order. The\n    class itself is excluded from the search; only its parents are checked. Get\n    fields from ``_declared_fields`` if available, else use ``__dict__``.\n\n    :param type klass: Class whose fields to retrieve\n    :param type field_class: Base field class\n    """\n    mro = inspect.getmro(klass)\n    # Loop over mro in reverse to maintain correct order of fields\n    return sum(\n        (\n            _get_fields(\n                getattr(base, \'_declared_fields\', base.__dict__),\n                field_class,\n                ordered=ordered\n            )\n            for base in mro[:0:-1]\n        ),\n        [],\n    )\n\n\nclass SchemaMeta(type):\n    """Metaclass for the Schema class. Binds the declared fields to\n    a ``_declared_fields`` attribute, which is a dictionary mapping attribute\n    names to field objects. Also sets the ``opts`` class attribute, which is\n    the Schema class\'s ``class Meta`` options.\n    """\n\n    def __new__(mcs, name, bases, attrs):\n        meta = attrs.get(\'Meta\')\n        ordered = getattr(meta, \'ordered\', False)\n        if not ordered:\n            # Inherit \'ordered\' option\n            # Warning: We loop through bases instead of MRO because we don\'t\n            # yet have access to the class object\n            # (i.e. can\'t call super before we have fields)\n            for base_ in bases:\n                if hasattr(base_, \'Meta\') and hasattr(base_.Meta, \'ordered\'):\n                    ordered = base_.Meta.ordered\n                    break\n            else:\n                ordered = False\n        cls_fields = _get_fields(attrs, base.FieldABC, pop=True, ordered=ordered)\n        klass = super(SchemaMeta, mcs).__new__(mcs, name, bases, attrs)\n        inherited_fields = _get_fields_by_mro(klass, base.FieldABC)\n\n        # Use getattr rather than attrs[\'Meta\'] so that we get inheritance for free\n        meta = getattr(klass, \'Meta\')\n        # Set klass.opts in __new__ rather than __init__ so that it is accessible in\n        # get_declared_fields\n        klass.opts = klass.OPTIONS_CLASS(meta)\n        # Add fields specifid in the `include` class Meta option\n        cls_fields += list(klass.opts.include.items())\n\n        dict_cls = OrderedDict if ordered else dict\n        # Assign _declared_fields on class\n        klass._declared_fields = mcs.get_declared_fields(\n            klass=klass,\n            cls_fields=cls_fields,\n            inherited_fields=inherited_fields,\n            dict_cls=dict_cls\n        )\n        return klass\n\n    @classmethod\n    def get_declared_fields(mcs, klass, cls_fields, inherited_fields, dict_cls):\n        """Returns a dictionary of field_name => `Field` pairs declard on the class.\n        This is exposed mainly so that plugins can add additional fields, e.g. fields\n        computed from class Meta options.\n\n        :param type klass: The class object.\n        :param dict cls_fields: The fields declared on the class, including those added\n            by the ``include`` class Meta option.\n        :param dict inherited_fileds: Inherited fields.\n        :param type dict_class: Either `dict` or `OrderedDict`, depending on the whether\n            the user specified `ordered=True`.\n        """\n        return dict_cls(inherited_fields + cls_fields)\n\n    # NOTE: self is the class object\n    def __init__(self, name, bases, attrs):\n        super(SchemaMeta, self).__init__(name, bases, attrs)\n        class_registry.register(name, self)\n        self._resolve_processors()\n\n    def _resolve_processors(self):\n        """Add in the decorated processors\n\n        By doing this after constructing the class, we let standard inheritance\n        do all the hard work.\n        """\n        mro = inspect.getmro(self)\n        self.__processors__ = defaultdict(list)\n        for attr_name in dir(self):\n            # Need to look up the actual descriptor, not whatever might be\n            # bound to the class. This needs to come from the __dict__ of the\n            # declaring class.\n            for parent in mro:\n                try:\n                    attr = parent.__dict__[attr_name]\n                except KeyError:\n                    continue\n                else:\n                    break\n            else:\n                # In case we didn\'t find the attribute and didn\'t break above.\n                # We should never hit this - it\'s just here for completeness\n                # to exclude the possibility of attr being undefined.\n                continue\n\n            try:\n                processor_tags = attr.__marshmallow_tags__\n            except AttributeError:\n                continue\n\n            for tag in processor_tags:\n                # Use name here so we can get the bound method later, in case\n                # the processor was a descriptor or something.\n                self.__processors__[tag].append(attr_name)\n\n\nclass SchemaOpts(object):\n    """class Meta options for the :class:`Schema`. Defines defaults."""\n\n    def __init__(self, meta):\n        self.fields = getattr(meta, \'fields\', ())\n        if not isinstance(self.fields, (list, tuple)):\n            raise ValueError("`fields` option must be a list or tuple.")\n        self.additional = getattr(meta, \'additional\', ())\n        if not isinstance(self.additional, (list, tuple)):\n            raise ValueError("`additional` option must be a list or tuple.")\n        if self.fields and self.additional:\n            raise ValueError("Cannot set both `fields` and `additional` options"\n                            " for the same Schema.")\n        self.exclude = getattr(meta, \'exclude\', ())\n        if not isinstance(self.exclude, (list, tuple)):\n            raise ValueError("`exclude` must be a list or tuple.")\n        self.strict = getattr(meta, \'strict\', False)\n        self.dateformat = getattr(meta, \'dateformat\', None)\n        self.json_module = getattr(meta, \'json_module\', json)\n        if hasattr(meta, \'skip_missing\'):\n            warnings.warn(\n                \'The skip_missing option is no longer necessary. Missing inputs passed to \'\n                \'Schema.dump will be excluded from the serialized output by default.\',\n                UserWarning\n            )\n        self.ordered = getattr(meta, \'ordered\', False)\n        self.index_errors = getattr(meta, \'index_errors\', True)\n        self.include = getattr(meta, \'include\', {})\n        self.load_only = getattr(meta, \'load_only\', ())\n        self.dump_only = getattr(meta, \'dump_only\', ())\n\n\nclass BaseSchema(base.SchemaABC):\n    """Base schema class with which to define custom schemas.\n\n    Example usage:\n\n    .. code-block:: python\n\n        import datetime as dt\n        from marshmallow import Schema, fields\n\n        class Album(object):\n            def __init__(self, title, release_date):\n                self.title = title\n                self.release_date = release_date\n\n        class AlbumSchema(Schema):\n            title = fields.Str()\n            release_date = fields.Date()\n\n        # Or, equivalently\n        class AlbumSchema2(Schema):\n            class Meta:\n                fields = ("title", "release_date")\n\n        album = Album("Beggars Banquet", dt.date(1968, 12, 6))\n        schema = AlbumSchema()\n        data, errors = schema.dump(album)\n        data  # {\'release_date\': \'1968-12-06\', \'title\': \'Beggars Banquet\'}\n\n    :param dict extra: A dict of extra attributes to bind to the serialized result.\n    :param tuple only: A list or tuple of fields to serialize. If `None`, all\n        fields will be serialized.\n    :param tuple exclude: A list or tuple of fields to exclude from the\n        serialized result.\n    :param str prefix: Optional prefix that will be prepended to all the\n        serialized field names.\n    :param bool strict: If `True`, raise errors if invalid data are passed in\n        instead of failing silently and storing the errors.\n    :param bool many: Should be set to `True` if ``obj`` is a collection\n        so that the object will be serialized to a list.\n    :param dict context: Optional context passed to :class:`fields.Method` and\n        :class:`fields.Function` fields.\n    :param tuple load_only: A list or tuple of fields to skip during serialization\n    :param tuple dump_only: A list or tuple of fields to skip during\n        deserialization, read-only fields\n\n    .. versionchanged:: 2.0.0\n        `__validators__`, `__preprocessors__`, and `__data_handlers__` are removed in favor of\n        `marshmallow.decorators.validates_schema`,\n        `marshmallow.decorators.pre_load` and `marshmallow.decorators.post_dump`.\n        `__accessor__` and `__error_handler__` are deprecated. Implement the\n        `handle_error` and `get_attribute` methods instead.\n        """\n    TYPE_MAPPING = {\n        text_type: fields.String,\n        binary_type: fields.String,\n        dt.datetime: fields.DateTime,\n        float: fields.Float,\n        bool: fields.Boolean,\n        tuple: fields.Raw,\n        list: fields.Raw,\n        set: fields.Raw,\n        int: fields.Integer,\n        uuid.UUID: fields.UUID,\n        dt.time: fields.Time,\n        dt.date: fields.Date,\n        dt.timedelta: fields.TimeDelta,\n        decimal.Decimal: fields.Decimal,\n    }\n\n    OPTIONS_CLASS = SchemaOpts\n\n    #: DEPRECATED: Custom error handler function. May be `None`.\n    __error_handler__ = None\n    #: DEPRECATED: Function used to get values of an object.\n    __accessor__ = None\n\n    class Meta(object):\n        """Options object for a Schema.\n\n        Example usage: ::\n\n            class Meta:\n                fields = ("id", "email", "date_created")\n                exclude = ("password", "secret_attribute")\n\n        Available options:\n\n        - ``fields``: Tuple or list of fields to include in the serialized result.\n        - ``additional``: Tuple or list of fields to include *in addition* to the\n            explicitly declared fields. ``additional`` and ``fields`` are\n            mutually-exclusive options.\n        - ``include``: Dictionary of additional fields to include in the schema. It is\n            usually better to define fields as class variables, but you may need to\n            use this option, e.g., if your fields are Python keywords. May be an\n            `OrderedDict`.\n        - ``exclude``: Tuple or list of fields to exclude in the serialized result.\n        - ``dateformat``: Date format for all DateTime fields that do not have their\n            date format explicitly specified.\n        - ``strict``: If `True`, raise errors during marshalling rather than\n            storing them.\n        - ``json_module``: JSON module to use for `loads` and `dumps`.\n            Defaults to the ``json`` module in the stdlib.\n        - ``ordered``: If `True`, order serialization output according to the\n            order in which fields were declared. Output of `Schema.dump` will be a\n            `collections.OrderedDict`.\n        - ``index_errors``: If `True`, errors dictionaries will include the index\n            of invalid items in a collection.\n        - ``load_only``: Tuple or list of fields to exclude from serialized results.\n        - ``dump_only``: Tuple or list of fields to exclude from deserialization\n        """\n        pass\n\n    def __init__(self, extra=None, only=(), exclude=(), prefix=\'\', strict=False,\n                 many=False, context=None, load_only=(), dump_only=()):\n        # copy declared fields from metaclass\n        self.declared_fields = copy.deepcopy(self._declared_fields)\n        self.many = many\n        self.only = only\n        self.exclude = exclude\n        self.prefix = prefix\n        self.strict = strict or self.opts.strict\n        self.ordered = self.opts.ordered\n        self.load_only = set(load_only) or set(self.opts.load_only)\n        self.dump_only = set(dump_only) or set(self.opts.dump_only)\n        #: Dictionary mapping field_names -> :class:`Field` objects\n        self.fields = self.dict_class()\n        #: Callable marshalling object\n        self._marshal = marshalling.Marshaller(\n            prefix=self.prefix\n        )\n        #: Callable unmarshalling object\n        self._unmarshal = marshalling.Unmarshaller()\n        if extra:\n            warnings.warn(\n                \'The `extra` argument is deprecated. Use a post_dump \'\n                \'method to add additional data instead.\',\n                DeprecationWarning\n            )\n        self.extra = extra\n        self.context = context or {}\n        self._update_fields(many=many)\n\n    def __repr__(self):\n        return \'<{ClassName}(many={self.many}, strict={self.strict})>\'.format(\n            ClassName=self.__class__.__name__, self=self\n        )\n\n    def _postprocess(self, data, many, obj):\n        if self.extra:\n            if many:\n                for each in data:\n                    each.update(self.extra)\n            else:\n                data.update(self.extra)\n        if self._marshal.errors:\n            # TODO: Remove self.__error_handler__ in a later release\n            error_handler = self.handle_error or self.__error_handler__\n            if callable(error_handler):\n                error_handler(self._marshal.errors, obj)\n\n        return data\n\n    @property\n    def dict_class(self):\n        return OrderedDict if self.ordered else dict\n\n    @property\n    def set_class(self):\n        return OrderedSet if self.ordered else set\n\n    ##### Override-able methods #####\n\n    def handle_error(self, error, data):\n        """Custom error handler function for the schema.\n\n        :param ValidationError error: The `ValidationError` raised during (de)serialization.\n        :param data: The original input data.\n\n        .. versionadded:: 2.0.0\n        """\n        pass\n\n    def get_attribute(self, attr, obj, default):\n        """Defines how to pull values from an object to serialize.\n\n        .. versionadded:: 2.0.0\n        """\n        return utils.get_value(attr, obj, default)\n\n    ##### Handler decorators (deprecated) #####\n\n    @classmethod\n    def error_handler(cls, func):\n        """Decorator that registers an error handler function for the schema.\n        The function receives the :class:`Schema` instance, a dictionary of errors,\n        and the serialized object (if serializing data) or data dictionary (if\n        deserializing data) as arguments.\n\n        Example: ::\n\n            class UserSchema(Schema):\n                email = fields.Email()\n\n            @UserSchema.error_handler\n            def handle_errors(schema, errors, obj):\n                raise ValueError(\'An error occurred while marshalling {}\'.format(obj))\n\n            user = User(email=\'invalid\')\n            UserSchema().dump(user)  # => raises ValueError\n            UserSchema().load({\'email\': \'bademail\'})  # raises ValueError\n\n        .. versionadded:: 0.7.0\n        .. deprecated:: 2.0.0\n            Set the ``error_handler`` class Meta option instead.\n        """\n        warnings.warn(\n            \'Schema.error_handler is deprecated. Set the error_handler class Meta option \'\n            \'instead.\', category=DeprecationWarning\n        )\n        cls.__error_handler__ = func\n        return func\n\n    @classmethod\n    def accessor(cls, func):\n        """Decorator that registers a function for pulling values from an object\n        to serialize. The function receives the :class:`Schema` instance, the\n        ``key`` of the value to get, the ``obj`` to serialize, and an optional\n        ``default`` value.\n\n        .. deprecated:: 2.0.0\n            Set the ``error_handler`` class Meta option instead.\n        """\n        warnings.warn(\n            \'Schema.accessor is deprecated. Set the accessor class Meta option \'\n            \'instead.\', category=DeprecationWarning\n        )\n        cls.__accessor__ = func\n        return func\n\n    ##### Serialization/Deserialization API #####\n\n    def dump(self, obj, many=None, update_fields=True, **kwargs):\n        """Serialize an object to native Python data types according to this\n        Schema\'s fields.\n\n        :param obj: The object to serialize.\n        :param bool many: Whether to serialize `obj` as a collection. If `None`, the value\n            for `self.many` is used.\n        :param bool update_fields: Whether to update the schema\'s field classes. Typically\n            set to `True`, but may be `False` when serializing a homogenous collection.\n            This parameter is used by `fields.Nested` to avoid multiple updates.\n        :return: A tuple of the form (``data``, ``errors``)\n        :rtype: `MarshalResult`, a `collections.namedtuple`\n\n        .. versionadded:: 1.0.0\n        """\n        many = self.many if many is None else bool(many)\n        if not many and utils.is_collection(obj) and not utils.is_keyed_tuple(obj):\n            warnings.warn(\'Implicit collection handling is deprecated. Set \'\n                            \'many=True to serialize a collection.\',\n                            category=DeprecationWarning)\n\n        if isinstance(obj, types.GeneratorType):\n            obj = list(obj)\n\n        processed_obj = self._invoke_dump_processors(PRE_DUMP, obj, many, original_data=obj)\n\n        if update_fields:\n            self._update_fields(processed_obj, many=many)\n\n        try:\n            preresult = self._marshal(\n                processed_obj,\n                self.fields,\n                many=many,\n                # TODO: Remove self.__accessor__ in a later release\n                accessor=self.get_attribute or self.__accessor__,\n                dict_class=self.dict_class,\n                index_errors=self.opts.index_errors,\n                **kwargs\n            )\n        except ValidationError as error:\n            errors = self._marshal.errors\n            preresult = error.data\n            if self.strict:\n                raise error\n        else:\n            errors = {}\n        result = self._postprocess(preresult, many, obj=obj)\n\n        result = self._invoke_dump_processors(POST_DUMP, result, many, original_data=obj)\n\n        return MarshalResult(result, errors)\n\n    def dumps(self, obj, many=None, update_fields=True, *args, **kwargs):\n        """Same as :meth:`dump`, except return a JSON-encoded string.\n\n        :param obj: The object to serialize.\n        :param bool many: Whether to serialize `obj` as a collection. If `None`, the value\n            for `self.many` is used.\n        :param bool update_fields: Whether to update the schema\'s field classes. Typically\n            set to `True`, but may be `False` when serializing a homogenous collection.\n            This parameter is used by `fields.Nested` to avoid multiple updates.\n        :return: A tuple of the form (``data``, ``errors``)\n        :rtype: `MarshalResult`, a `collections.namedtuple`\n\n        .. versionadded:: 1.0.0\n        """\n        deserialized, errors = self.dump(obj, many=many, update_fields=update_fields)\n        ret = self.opts.json_module.dumps(deserialized, *args, **kwargs)\n        return MarshalResult(ret, errors)\n\n    def load(self, data, many=None):\n        """Deserialize a data structure to an object defined by this Schema\'s\n        fields and :meth:`make_object`.\n\n        :param dict data: The data to deserialize.\n        :param bool many: Whether to deserialize `data` as a collection. If `None`, the\n            value for `self.many` is used.\n        :return: A tuple of the form (``data``, ``errors``)\n        :rtype: `UnmarshalResult`, a `collections.namedtuple`\n\n        .. versionadded:: 1.0.0\n        """\n        result, errors = self._do_load(data, many, postprocess=True)\n        return UnmarshalResult(data=result, errors=errors)\n\n    def loads(self, json_data, many=None, *args, **kwargs):\n        """Same as :meth:`load`, except it takes a JSON string as input.\n\n        :param str json_data: A JSON string of the data to deserialize.\n        :param bool many: Whether to deserialize `obj` as a collection. If `None`, the\n            value for `self.many` is used.\n        :return: A tuple of the form (``data``, ``errors``)\n        :rtype: `UnmarshalResult`, a `collections.namedtuple`\n\n        .. versionadded:: 1.0.0\n        """\n        data = self.opts.json_module.loads(json_data, *args, **kwargs)\n        return self.load(data, many=many)\n\n    def validate(self, data, many=None):\n        """Validate `data` against the schema, returning a dictionary of\n        validation errors.\n\n        :param dict data: The data to validate.\n        :param bool many: Whether to validate `data` as a collection. If `None`, the\n            value for `self.many` is used.\n        :return: A dictionary of validation errors.\n        :rtype: dict\n\n        .. versionadded:: 1.1.0\n        """\n        _, errors = self._do_load(data, many, postprocess=False)\n        return errors\n\n    ##### Private Helpers #####\n\n    def _do_load(self, data, many=None, postprocess=True):\n        """Deserialize `data`, returning the deserialized result and a dictonary of\n        validation errors.\n\n        :param data: The data to deserialize.\n        :param bool many: Whether to deserialize `data` as a collection. If `None`, the\n            value for `self.many` is used.\n        :param bool postprocess: Whether to run post_load methods..\n        :return: A tuple of the form (`data`, `errors`)\n        """\n        many = self.many if many is None else bool(many)\n\n        processed_data = self._invoke_load_processors(PRE_LOAD, data, many, original_data=data)\n\n        try:\n            result = self._unmarshal(\n                processed_data,\n                self.fields,\n                many=many,\n                dict_class=self.dict_class,\n                index_errors=self.opts.index_errors,\n            )\n        except ValidationError as error:\n            result = error.data\n        else:\n            errors = {}\n        self._invoke_field_validators(data=result, many=many)\n        errors = self._unmarshal.errors\n        # Run schema-level migration\n        try:\n            self._invoke_validators(pass_many=True, data=result, original_data=data, many=many)\n        except ValidationError as err:\n            errors.update(err.messages)\n        try:\n            self._invoke_validators(pass_many=False, data=result, original_data=data, many=many)\n        except ValidationError as err:\n            errors.update(err.messages)\n        if errors:\n            # TODO: Remove self.__error_handler__ in a later release\n            if self.__error_handler__ and callable(self.__error_handler__):\n                self.__error_handler__(errors, data)\n            exc = ValidationError(\n                errors,\n                field_names=self._unmarshal.error_field_names,\n                fields=self._unmarshal.error_fields,\n                data=data\n            )\n            self.handle_error(exc, data)\n            if self.strict:\n                raise exc\n\n        if not errors and postprocess:\n            result = self._invoke_load_processors(POST_LOAD, result, many, original_data=data)\n\n        return result, errors\n\n    def _update_fields(self, obj=None, many=False):\n        """Update fields based on the passed in object."""\n        if self.only:\n            # Return only fields specified in only option\n            if self.opts.fields:\n                field_names = self.set_class(self.opts.fields) & self.set_class(self.only)\n            else:\n                field_names = self.set_class(self.only)\n        elif self.opts.fields:\n            # Return fields specified in fields option\n            field_names = self.set_class(self.opts.fields)\n        elif self.opts.additional:\n            # Return declared fields + additional fields\n            field_names = (self.set_class(self.declared_fields.keys()) |\n                            self.set_class(self.opts.additional))\n        else:\n            field_names = self.set_class(self.declared_fields.keys())\n\n        # If "exclude" option or param is specified, remove those fields\n        excludes = set(self.opts.exclude) | set(self.exclude)\n        if excludes:\n            field_names = field_names - excludes\n        ret = self.__filter_fields(field_names, obj, many=many)\n        # Set parents\n        self.__set_field_attrs(ret)\n        self.fields = ret\n        return self.fields\n\n    def on_bind_field(self, field_name, field_obj):\n        """Hook to modify a field when it is bound to the `Schema`. No-op by default."""\n        return None\n\n    def __set_field_attrs(self, fields_dict):\n        """Bind fields to the schema, setting any necessary attributes\n        on the fields (e.g. parent and name).\n\n        Also set field load_only and dump_only values if field_name was\n        specified in ``class Meta``.\n        """\n        for field_name, field_obj in iteritems(fields_dict):\n            try:\n                if field_name in self.load_only:\n                    field_obj.load_only = True\n                if field_name in self.dump_only:\n                    field_obj.dump_only = True\n                self.on_bind_field(field_name, field_obj)\n                field_obj._add_to_schema(field_name, self)\n            except TypeError:\n                # field declared as a class, not an instance\n                if (isinstance(field_obj, type) and\n                        issubclass(field_obj, base.FieldABC)):\n                    msg = (\'Field for "{0}" must be declared as a \'\n                           \'Field instance, not a class. \'\n                           \'Did you mean "fields.{1}()"?\'\n                           .format(field_name, field_obj.__name__))\n                    raise TypeError(msg)\n        return fields_dict\n\n    def __filter_fields(self, field_names, obj, many=False):\n        """Return only those field_name:field_obj pairs specified by\n        ``field_names``.\n\n        :param set field_names: Field names to include in the final\n            return dictionary.\n        :returns: An dict of field_name:field_obj pairs.\n        """\n        if obj and many:\n            try:  # Homogeneous collection\n                obj_prototype = next(iter(obj))\n            except StopIteration:  # Nothing to serialize\n                return self.declared_fields\n            obj = obj_prototype\n        ret = self.dict_class()\n        for key in field_names:\n            if key in self.declared_fields:\n                ret[key] = self.declared_fields[key]\n            else:  # Implicit field creation (class Meta \'fields\' or \'additional\')\n                if obj:\n                    attribute_type = None\n                    try:\n                        if isinstance(obj, Mapping):\n                            attribute_type = type(obj[key])\n                        else:\n                            attribute_type = type(getattr(obj, key))\n                    except (AttributeError, KeyError) as err:\n                        err_type = type(err)\n                        raise err_type(\n                            \'"{0}" is not a valid field for {1}.\'.format(key, obj))\n                    field_obj = self.TYPE_MAPPING.get(attribute_type, fields.Field)()\n                else:  # Object is None\n                    field_obj = fields.Field()\n                # map key -> field (default to Raw)\n                ret[key] = field_obj\n        return ret\n\n    def _invoke_dump_processors(self, tag_name, data, many, original_data=None):\n        # The pass_many post-dump processors may do things like add an envelope, so\n        # invoke those after invoking the non-pass_many processors which will expect\n        # to get a list of items.\n        data = self._invoke_processors(tag_name, pass_many=False,\n            data=data, many=many, original_data=original_data)\n        data = self._invoke_processors(tag_name, pass_many=True,\n            data=data, many=many, original_data=original_data)\n        return data\n\n    def _invoke_load_processors(self, tag_name, data, many, original_data=None):\n        # This has to invert the order of the dump processors, so run the pass_many\n        # processors first.\n        data = self._invoke_processors(tag_name, pass_many=True,\n            data=data, many=many, original_data=original_data)\n        data = self._invoke_processors(tag_name, pass_many=False,\n            data=data, many=many, original_data=original_data)\n        return data\n\n    def _invoke_field_validators(self, data, many):\n        for attr_name in self.__processors__[(VALIDATES, False)]:\n            validator = getattr(self, attr_name)\n            validator_kwargs = validator.__marshmallow_kwargs__[(VALIDATES, False)]\n            field_name = validator_kwargs[\'field_name\']\n\n            try:\n                field_obj = self.fields[field_name]\n            except KeyError:\n                raise ValueError(\'"{0}" field does not exist.\'.format(field_name))\n\n            if many:\n                for idx, item in enumerate(data):\n                    try:\n                        value = item[field_name]\n                    except KeyError:\n                        pass\n                    else:\n                        self._unmarshal.call_and_store(\n                            getter_func=validator,\n                            data=value,\n                            field_name=field_name,\n                            field_obj=field_obj,\n                            index=(idx if self.opts.index_errors else None)\n                        )\n            else:\n                try:\n                    value = data[field_name]\n                except KeyError:\n                    pass\n                else:\n                    self._unmarshal.call_and_store(\n                        getter_func=validator,\n                        data=value,\n                        field_name=field_name,\n                        field_obj=field_obj\n                    )\n\n    def _invoke_validators(self, pass_many, data, original_data, many):\n        errors = {}\n        for attr_name in self.__processors__[(VALIDATES_SCHEMA, pass_many)]:\n            validator = getattr(self, attr_name)\n            validator_kwargs = validator.__marshmallow_kwargs__[(VALIDATES_SCHEMA, pass_many)]\n            pass_original = validator_kwargs.get(\'pass_original\', False)\n            if pass_many:\n                validator = partial(validator, many=many)\n            if many:\n                for idx, item in enumerate(data):\n                    try:\n                        self._unmarshal.run_validator(validator,\n                                                  item, original_data, self.fields, many=many,\n                                                  index=idx, pass_original=pass_original)\n                    except ValidationError as err:\n                        errors.update(err.messages)\n            else:\n                try:\n                    self._unmarshal.run_validator(validator,\n                                              data, original_data, self.fields, many=many,\n                                              pass_original=pass_original)\n                except ValidationError as err:\n                    errors.update(err.messages)\n        if errors:\n            raise ValidationError(errors)\n        return None\n\n    def _invoke_processors(self, tag_name, pass_many, data, many, original_data=None):\n        for attr_name in self.__processors__[(tag_name, pass_many)]:\n            # This will be a bound method.\n            processor = getattr(self, attr_name)\n\n            processor_kwargs = processor.__marshmallow_kwargs__[(tag_name, pass_many)]\n            pass_original = processor_kwargs.get(\'pass_original\', False)\n\n            if pass_many:\n                if pass_original:\n                    data = utils.if_none(processor(data, many, original_data), data)\n                else:\n                    data = utils.if_none(processor(data, many), data)\n            elif many:\n                if pass_original:\n                    data = [utils.if_none(processor(item, original_data), item)\n                            for item in data]\n                else:\n                    data = [utils.if_none(processor(item), item) for item in data]\n            else:\n                if pass_original:\n                    data = utils.if_none(processor(data, original_data), data)\n                else:\n                    data = utils.if_none(processor(data), data)\n        return data\n\n\nclass Schema(with_metaclass(SchemaMeta, BaseSchema)):\n    __doc__ = BaseSchema.__doc__\n',
            'tests/test_deserialization.py': '# -*- coding: utf-8 -*-\nimport datetime as dt\nimport uuid\nimport decimal\n\nimport pytest\n\nfrom marshmallow import fields, utils, Schema, validate\nfrom marshmallow.exceptions import ValidationError\nfrom marshmallow.compat import basestring\n\nfrom tests.base import (\n    assert_almost_equal,\n    assert_date_equal,\n    assert_datetime_equal,\n    assert_time_equal,\n    central,\n    ALL_FIELDS,\n    User,\n    DummyModel,\n)\n\nclass TestDeserializingNone:\n\n    @pytest.mark.parametrize(\'FieldClass\', ALL_FIELDS)\n    def test_fields_allow_none_deserialize_to_none(self, FieldClass):\n        if FieldClass == fields.FormattedString:\n            field = FieldClass(src_str=\'foo\', allow_none=True)\n        else:\n            field = FieldClass(allow_none=True)\n        field.deserialize(None) is None\n\n    # https://github.com/marshmallow-code/marshmallow/issues/111\n    @pytest.mark.parametrize(\'FieldClass\', ALL_FIELDS)\n    def test_fields_dont_allow_none_by_default(self, FieldClass):\n        # by default, allow_none=False\n        if FieldClass == fields.FormattedString:\n            field = FieldClass(src_str=\'foo\')\n        else:\n            field = FieldClass()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(None)\n        assert \'Field may not be null.\' in str(excinfo)\n\n    def test_allow_none_is_true_if_missing_is_true(self):\n        field = fields.Field(missing=None)\n        assert field.allow_none is True\n        field.deserialize(None) is None\n\n    def test_list_field_deserialize_none_to_empty_list(self):\n        field = fields.List(fields.String(allow_none=True), allow_none=True)\n        assert field.deserialize(None) is None\n\n\nclass TestFieldDeserialization:\n\n    def test_float_field_deserialization(self):\n        field = fields.Float()\n        assert_almost_equal(field.deserialize(\'12.3\'), 12.3)\n        assert_almost_equal(field.deserialize(12.3), 12.3)\n\n    @pytest.mark.parametrize(\'in_val\',\n    [\n        \'bad\',\n        \'\',\n        {},\n    ])\n    def test_invalid_float_field_deserialization(self, in_val):\n        field = fields.Float()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_val)\n        assert excinfo.value.args[0] == \'Not a valid number.\'\n\n    def test_integer_field_deserialization(self):\n        field = fields.Integer()\n        assert field.deserialize(\'42\') == 42\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'42.0\')\n        assert excinfo.value.args[0] == \'Not a valid integer.\'\n        with pytest.raises(ValidationError):\n            field.deserialize(\'bad\')\n        assert excinfo.value.args[0] == \'Not a valid integer.\'\n        with pytest.raises(ValidationError):\n            field.deserialize({})\n        assert excinfo.value.args[0] == \'Not a valid integer.\'\n\n    def test_decimal_field_deserialization(self):\n        m1 = 12\n        m2 = \'12.355\'\n        m3 = decimal.Decimal(1)\n        m4 = \'abc\'\n        m5 = [1, 2]\n\n        field = fields.Decimal()\n        assert isinstance(field.deserialize(m1), decimal.Decimal)\n        assert field.deserialize(m1) == decimal.Decimal(12)\n        assert isinstance(field.deserialize(m2), decimal.Decimal)\n        assert field.deserialize(m2) == decimal.Decimal(\'12.355\')\n        assert isinstance(field.deserialize(m3), decimal.Decimal)\n        assert field.deserialize(m3) == decimal.Decimal(1)\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(m4)\n        assert excinfo.value.args[0] == \'Not a valid number.\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(m5)\n        assert excinfo.value.args[0] == \'Not a valid number.\'\n\n    def test_decimal_field_with_places(self):\n        m1 = 12\n        m2 = \'12.355\'\n        m3 = decimal.Decimal(1)\n        m4 = \'abc\'\n        m5 = [1, 2]\n\n        field = fields.Decimal(1)\n        assert isinstance(field.deserialize(m1), decimal.Decimal)\n        assert field.deserialize(m1) == decimal.Decimal(12)\n        assert isinstance(field.deserialize(m2), decimal.Decimal)\n        assert field.deserialize(m2) == decimal.Decimal(\'12.4\')\n        assert isinstance(field.deserialize(m3), decimal.Decimal)\n        assert field.deserialize(m3) == decimal.Decimal(1)\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(m4)\n        assert excinfo.value.args[0] == \'Not a valid number.\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(m5)\n        assert excinfo.value.args[0] == \'Not a valid number.\'\n\n    def test_decimal_field_with_places_and_rounding(self):\n        m1 = 12\n        m2 = \'12.355\'\n        m3 = decimal.Decimal(1)\n        m4 = \'abc\'\n        m5 = [1, 2]\n\n        field = fields.Decimal(1, decimal.ROUND_DOWN)\n        assert isinstance(field.deserialize(m1), decimal.Decimal)\n        assert field.deserialize(m1) == decimal.Decimal(12)\n        assert isinstance(field.deserialize(m2), decimal.Decimal)\n        assert field.deserialize(m2) == decimal.Decimal(\'12.3\')\n        assert isinstance(field.deserialize(m3), decimal.Decimal)\n        assert field.deserialize(m3) == decimal.Decimal(1)\n        with pytest.raises(ValidationError):\n            field.deserialize(m4)\n        with pytest.raises(ValidationError):\n            field.deserialize(m5)\n\n    def test_decimal_field_deserialization_string(self):\n        m1 = 12\n        m2 = \'12.355\'\n        m3 = decimal.Decimal(1)\n        m4 = \'abc\'\n        m5 = [1, 2]\n\n        field = fields.Decimal(as_string=True)\n        assert isinstance(field.deserialize(m1), decimal.Decimal)\n        assert field.deserialize(m1) == decimal.Decimal(12)\n        assert isinstance(field.deserialize(m2), decimal.Decimal)\n        assert field.deserialize(m2) == decimal.Decimal(\'12.355\')\n        assert isinstance(field.deserialize(m3), decimal.Decimal)\n        assert field.deserialize(m3) == decimal.Decimal(1)\n        with pytest.raises(ValidationError):\n            field.deserialize(m4)\n        with pytest.raises(ValidationError):\n            field.deserialize(m5)\n\n    def test_decimal_field_special_values(self):\n        m1 = \'-NaN\'\n        m2 = \'NaN\'\n        m3 = \'-sNaN\'\n        m4 = \'sNaN\'\n        m5 = \'-Infinity\'\n        m6 = \'Infinity\'\n        m7 = \'-0\'\n\n        field = fields.Decimal(places=2, allow_nan=True)\n\n        m1d = field.deserialize(m1)\n        assert isinstance(m1d, decimal.Decimal)\n        assert m1d.is_qnan() and not m1d.is_signed()\n\n        m2d = field.deserialize(m2)\n        assert isinstance(m2d, decimal.Decimal)\n        assert m2d.is_qnan() and not m2d.is_signed()\n\n        m3d = field.deserialize(m3)\n        assert isinstance(m3d, decimal.Decimal)\n        assert m3d.is_qnan() and not m3d.is_signed()\n\n        m4d = field.deserialize(m4)\n        assert isinstance(m4d, decimal.Decimal)\n        assert m4d.is_qnan() and not m4d.is_signed()\n\n        m5d = field.deserialize(m5)\n        assert isinstance(m5d, decimal.Decimal)\n        assert m5d.is_infinite() and m5d.is_signed()\n\n        m6d = field.deserialize(m6)\n        assert isinstance(m6d, decimal.Decimal)\n        assert m6d.is_infinite() and not m6d.is_signed()\n\n        m7d = field.deserialize(m7)\n        assert isinstance(m7d, decimal.Decimal)\n        assert m7d.is_zero() and m7d.is_signed()\n\n    def test_decimal_field_special_values_not_permitted(self):\n        m1 = \'-NaN\'\n        m2 = \'NaN\'\n        m3 = \'-sNaN\'\n        m4 = \'sNaN\'\n        m5 = \'-Infinity\'\n        m6 = \'Infinity\'\n        m7 = \'-0\'\n\n        field = fields.Decimal(places=2)\n\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(m1)\n        assert str(excinfo.value.args[0]) == \'Special numeric values are not permitted.\'\n        with pytest.raises(ValidationError):\n            field.deserialize(m2)\n        with pytest.raises(ValidationError):\n            field.deserialize(m3)\n        with pytest.raises(ValidationError):\n            field.deserialize(m4)\n        with pytest.raises(ValidationError):\n            field.deserialize(m5)\n        with pytest.raises(ValidationError):\n            field.deserialize(m6)\n\n        m7d = field.deserialize(m7)\n        assert isinstance(m7d, decimal.Decimal)\n        assert m7d.is_zero() and m7d.is_signed()\n\n    def test_string_field_deserialization(self):\n        field = fields.String()\n        assert field.deserialize(\'foo\') == \'foo\'\n        assert field.deserialize(b\'foo\') == \'foo\'\n\n        # https://github.com/marshmallow-code/marshmallow/issues/231\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(42)\n        assert excinfo.value.args[0] == \'Not a valid string.\'\n\n        with pytest.raises(ValidationError):\n            field.deserialize({})\n\n    def test_boolean_field_deserialization(self):\n        field = fields.Boolean()\n        assert field.deserialize(True) is True\n        assert field.deserialize(False) is False\n        assert field.deserialize(\'True\') is True\n        assert field.deserialize(\'False\') is False\n        assert field.deserialize(\'true\') is True\n        assert field.deserialize(\'false\') is False\n        assert field.deserialize(\'1\') is True\n        assert field.deserialize(\'0\') is False\n        assert field.deserialize(1) is True\n        assert field.deserialize(0) is False\n\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize({})\n        assert excinfo.value.args[0] == \'Not a valid boolean.\'\n\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(42)\n\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'invalid-string\')\n\n    def test_boolean_field_deserialization_with_custom_truthy_values(self):\n        class MyBoolean(fields.Boolean):\n            truthy = set([\'yep\'])\n        field = MyBoolean()\n        assert field.deserialize(\'yep\') is True\n\n    @pytest.mark.parametrize(\'in_val\',\n    [\n        \'notvalid\',\n        123\n    ])\n    def test_boolean_field_deserialization_with_custom_truthy_values_invalid(\n            self, in_val):\n        class MyBoolean(fields.Boolean):\n            truthy = set([\'yep\'])\n        field = MyBoolean()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_val)\n        expected_msg = \'Not a valid boolean.\'\n        assert str(excinfo.value.args[0]) == expected_msg\n        field2 = MyBoolean(error_messages={\'invalid\': \'bad input\'})\n        with pytest.raises(ValidationError) as excinfo:\n            field2.deserialize(in_val)\n        assert str(excinfo.value.args[0]) == \'bad input\'\n\n    @pytest.mark.parametrize(\'in_value\',\n    [\n        \'not-a-datetime\',\n        42,\n        \'\',\n        [],\n    ])\n    def test_invalid_datetime_deserialization(self, in_value):\n        field = fields.DateTime()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_value)\n        msg = \'Not a valid datetime.\'.format(in_value)\n        assert msg in str(excinfo)\n\n    def test_custom_date_format_datetime_field_deserialization(self):\n\n        dtime = dt.datetime.now()\n        datestring = dtime.strftime(\'%H:%M:%S %Y-%m-%d\')\n\n        field = fields.DateTime(format=\'%d-%m-%Y %H:%M:%S\')\n        #deserialization should fail when datestring is not of same format\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(datestring)\n        msg = \'Not a valid datetime.\'.format(datestring)\n        assert msg in str(excinfo)\n        field = fields.DateTime(format=\'%H:%M:%S %Y-%m-%d\')\n        assert_datetime_equal(field.deserialize(datestring), dtime)\n\n        field = fields.DateTime()\n        if utils.dateutil_available:\n            assert_datetime_equal(field.deserialize(datestring), dtime)\n        else:\n            assert msg in str(excinfo)\n\n    @pytest.mark.parametrize(\'fmt\', [\'rfc\', \'rfc822\'])\n    def test_rfc_datetime_field_deserialization(self, fmt):\n        dtime = dt.datetime.now()\n        datestring = utils.rfcformat(dtime)\n        field = fields.DateTime(format=fmt)\n        assert_datetime_equal(field.deserialize(datestring), dtime)\n\n    @pytest.mark.parametrize(\'fmt\', [\'iso\', \'iso8601\'])\n    def test_iso_datetime_field_deserialization(self, fmt):\n        dtime = dt.datetime.now()\n        datestring = dtime.isoformat()\n        field = fields.DateTime(format=fmt)\n        assert_datetime_equal(field.deserialize(datestring), dtime)\n\n    def test_localdatetime_field_deserialization(self):\n        dtime = dt.datetime.now()\n        localized_dtime = central.localize(dtime)\n        field = fields.DateTime(format=\'iso\')\n        result = field.deserialize(localized_dtime.isoformat())\n        assert_datetime_equal(result, dtime)\n        # If dateutil is used, the datetime will not be naive\n        if utils.dateutil_available:\n            assert result.tzinfo is not None\n\n    def test_time_field_deserialization(self):\n        field = fields.Time()\n        t = dt.time(1, 23, 45)\n        t_formatted = t.isoformat()\n        result = field.deserialize(t_formatted)\n        assert isinstance(result, dt.time)\n        assert_time_equal(result, t)\n        # With microseconds\n        t2 = dt.time(1, 23, 45, 6789)\n        t2_formatted = t2.isoformat()\n        result2 = field.deserialize(t2_formatted)\n        assert_time_equal(result2, t2)\n\n    @pytest.mark.parametrize(\'in_data\',\n    [\n        \'badvalue\',\n        \'\',\n        [],\n        42,\n    ])\n    def test_invalid_time_field_deserialization(self, in_data):\n        field = fields.Time()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_data)\n        assert excinfo.value.args[0] == \'Not a valid time.\'\n\n    def test_timedelta_field_deserialization(self):\n        field = fields.TimeDelta()\n        result = field.deserialize(\'42\')\n        assert isinstance(result, dt.timedelta)\n        assert result.days == 0\n        assert result.seconds == 42\n        assert result.microseconds == 0\n\n        field = fields.TimeDelta(fields.TimeDelta.SECONDS)\n        result = field.deserialize(100000)\n        assert result.days == 1\n        assert result.seconds == 13600\n        assert result.microseconds == 0\n\n        field = fields.TimeDelta(fields.TimeDelta.DAYS)\n        result = field.deserialize(\'-42\')\n        assert isinstance(result, dt.timedelta)\n        assert result.days == -42\n        assert result.seconds == 0\n        assert result.microseconds == 0\n\n        field = fields.TimeDelta(fields.TimeDelta.MICROSECONDS)\n        result = field.deserialize(10 ** 6 + 1)\n        assert isinstance(result, dt.timedelta)\n        assert result.days == 0\n        assert result.seconds == 1\n        assert result.microseconds == 1\n\n        field = fields.TimeDelta(fields.TimeDelta.MICROSECONDS)\n        result = field.deserialize(86400 * 10 ** 6 + 1)\n        assert isinstance(result, dt.timedelta)\n        assert result.days == 1\n        assert result.seconds == 0\n        assert result.microseconds == 1\n\n        field = fields.TimeDelta()\n        result = field.deserialize(12.9)\n        assert isinstance(result, dt.timedelta)\n        assert result.days == 0\n        assert result.seconds == 12\n        assert result.microseconds == 0\n\n    @pytest.mark.parametrize(\'in_value\',\n    [\n        \'\',\n        \'badvalue\',\n        [],\n        9999999999,\n    ])\n    def test_invalid_timedelta_field_deserialization(self, in_value):\n        field = fields.TimeDelta(fields.TimeDelta.DAYS)\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_value)\n        assert excinfo.value.args[0] == \'Not a valid period of time.\'\n\n    def test_date_field_deserialization(self):\n        field = fields.Date()\n        d = dt.date(2014, 8, 21)\n        iso_date = d.isoformat()\n        result = field.deserialize(iso_date)\n        assert isinstance(result, dt.date)\n        assert_date_equal(result, d)\n\n    @pytest.mark.parametrize(\'in_value\',\n    [\n        \'\',\n        123,\n        [],\n    ])\n    def test_invalid_date_field_deserialization(self, in_value):\n        field = fields.Date()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_value)\n        msg = \'Not a valid date.\'\n        assert excinfo.value.args[0] == msg\n\n    def test_dict_field_deserialization(self):\n        field = fields.Dict()\n        assert field.deserialize({"foo": "bar"}) == {"foo": "bar"}\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'baddict\')\n        assert excinfo.value.args[0] == \'Not a valid mapping type.\'\n\n    def test_url_field_deserialization(self):\n        field = fields.Url()\n        assert field.deserialize(\'https://duckduckgo.com\') == \'https://duckduckgo.com\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'badurl\')\n        assert excinfo.value.args[0][0] == \'Not a valid URL.\'\n        # Relative URLS not allowed by default\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'/foo/bar\')\n        assert excinfo.value.args[0][0] == \'Not a valid URL.\'\n\n    def test_relative_url_field_deserialization(self):\n        field = fields.Url(relative=True)\n        assert field.deserialize(\'/foo/bar\') == \'/foo/bar\'\n\n    def test_email_field_deserialization(self):\n        field = fields.Email()\n        assert field.deserialize(\'foo@bar.com\') == \'foo@bar.com\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'invalidemail\')\n        assert excinfo.value.args[0][0] == \'Not a valid email address.\'\n\n    def test_function_field_deserialization_is_noop_by_default(self):\n        field = fields.Function(lambda x: None)\n        # Default is noop\n        assert field.deserialize(\'foo\') == \'foo\'\n        assert field.deserialize(42) == 42\n\n    def test_function_field_deserialization_with_callable(self):\n        field = fields.Function(lambda x: None,\n                                deserialize=lambda val: val.upper())\n        assert field.deserialize(\'foo\') == \'FOO\'\n\n    def test_uuid_field_deserialization(self):\n        field = fields.UUID()\n        uuid_str = str(uuid.uuid4())\n        result = field.deserialize(uuid_str)\n        assert isinstance(result, uuid.UUID)\n        assert str(result) == uuid_str\n\n    @pytest.mark.parametrize(\'in_value\',\n    [\n        \'malformed\',\n        123,\n        [],\n    ])\n    def test_invalid_uuid_deserialization(self, in_value):\n        field = fields.UUID()\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(in_value)\n\n        assert excinfo.value.args[0] == \'Not a valid UUID.\'\n\n    def test_deserialization_function_must_be_callable(self):\n        with pytest.raises(ValueError):\n            fields.Function(lambda x: None,\n                            deserialize=\'notvalid\')\n\n    def test_method_field_deserialization_is_noop_by_default(self):\n        class MiniUserSchema(Schema):\n            uppername = fields.Method(\'uppercase_name\')\n\n            def uppercase_name(self, obj):\n                return obj.upper()\n        user = User(name=\'steve\')\n        s = MiniUserSchema(user)\n        assert s.fields[\'uppername\'].deserialize(\'steve\') == \'steve\'\n\n    def test_deserialization_method(self):\n        class MiniUserSchema(Schema):\n            uppername = fields.Method(\'uppercase_name\', deserialize=\'lowercase_name\')\n\n            def uppercase_name(self, obj):\n                return obj.name.upper()\n\n            def lowercase_name(self, value):\n                return value.lower()\n\n        s = MiniUserSchema()\n        assert s.fields[\'uppername\'].deserialize(\'STEVE\') == \'steve\'\n\n    def test_deserialization_method_must_be_a_method(self):\n        class BadSchema(Schema):\n            uppername = fields.Method(\'uppercase_name\', deserialize=\'lowercase_name\')\n\n        s = BadSchema()\n        with pytest.raises(ValueError):\n            s.fields[\'uppername\'].deserialize(\'STEVE\')\n\n    def test_query_select_field_func_key_deserialization(self):\n        query = lambda: [DummyModel(ch) for ch in \'abc\']\n\n        field = fields.QuerySelect(query, str)\n        assert field.deserialize(\'bar a\') == DummyModel(\'a\')\n        assert field.deserialize(\'bar b\') == DummyModel(\'b\')\n        assert field.deserialize(\'bar c\') == DummyModel(\'c\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'bar d\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'c\')\n        assert list(field.keys()) == [\'bar \' + ch for ch in \'abc\']\n        assert list(field.results()) == [DummyModel(ch) for ch in \'abc\']\n        assert list(field.pairs()) == [(\'bar \' + ch, DummyModel(ch)) for ch in \'abc\']\n        assert list(field.labels()) == [(\'bar \' + ch, \'bar \' + ch) for ch in \'abc\']\n        assert list(field.labels(\'foo\')) == [(\'bar \' + ch, ch) for ch in \'abc\']\n        assert list(field.labels(str)) == [(\'bar \' + ch, \'bar \' + ch) for ch in \'abc\']\n\n    def test_query_select_field_string_key_deserialization(self):\n        query = lambda: [DummyModel(ch) for ch in \'abc\']\n\n        field = fields.QuerySelect(query, \'foo\')\n        assert field.deserialize(\'a\') == DummyModel(\'a\')\n        assert field.deserialize(\'b\') == DummyModel(\'b\')\n        assert field.deserialize(\'c\') == DummyModel(\'c\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'d\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'bar d\')\n        assert list(field.keys()) == [ch for ch in \'abc\']\n        assert list(field.results()) == [DummyModel(ch) for ch in \'abc\']\n        assert list(field.pairs()) == [(ch, DummyModel(ch)) for ch in \'abc\']\n        assert list(field.labels()) == [(ch, \'bar \' + ch) for ch in \'abc\']\n        assert list(field.labels(\'foo\')) == [(ch, ch) for ch in \'abc\']\n        assert list(field.labels(str)) == [(ch, \'bar \' + ch) for ch in \'abc\']\n\n    def test_query_select_list_field_func_key_deserialization(self):\n        query = lambda: [DummyModel(ch) for ch in \'abecde\']\n\n        field = fields.QuerySelectList(query, str)\n        assert field.deserialize([\'bar a\', \'bar c\', \'bar b\']) == \\\n               [DummyModel(\'a\'), DummyModel(\'c\'), DummyModel(\'b\')]\n        assert field.deserialize([\'bar d\', \'bar e\', \'bar e\']) == \\\n               [DummyModel(\'d\'), DummyModel(\'e\'), DummyModel(\'e\')]\n        assert field.deserialize([]) == []\n        with pytest.raises(ValidationError):\n            field.deserialize([\'a\', \'b\', \'f\'])\n        with pytest.raises(ValidationError):\n            field.deserialize([\'a\', \'b\', \'b\'])\n\n    def test_query_select_list_field_string_key_deserialization(self):\n        query = lambda: [DummyModel(ch) for ch in \'abecde\']\n\n        field = fields.QuerySelectList(query, \'foo\')\n        assert field.deserialize([\'a\', \'c\', \'b\']) == \\\n               [DummyModel(\'a\'), DummyModel(\'c\'), DummyModel(\'b\')]\n        assert field.deserialize([\'d\', \'e\', \'e\']) == \\\n               [DummyModel(\'d\'), DummyModel(\'e\'), DummyModel(\'e\')]\n        assert field.deserialize([]) == []\n        with pytest.raises(ValidationError):\n            field.deserialize([\'a\', \'b\', \'f\'])\n        with pytest.raises(ValidationError):\n            field.deserialize([\'a\', \'b\', \'b\'])\n\n    def test_datetime_list_field_deserialization(self):\n        dtimes = dt.datetime.now(), dt.datetime.now(), dt.datetime.utcnow()\n        dstrings = [each.isoformat() for each in dtimes]\n        field = fields.List(fields.DateTime())\n        result = field.deserialize(dstrings)\n        assert all([isinstance(each, dt.datetime) for each in result])\n        for actual, expected in zip(result, dtimes):\n            assert_date_equal(actual, expected)\n\n    def test_list_field_deserialize_invalid_item(self):\n        field = fields.List(fields.DateTime)\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize([\'badvalue\'])\n        assert excinfo.value.args[0] == \'Not a valid datetime.\'\n\n        field = fields.List(fields.Str())\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize([\'good\', 42])\n        assert excinfo.value.args[0] == \'Not a valid string.\'\n\n    @pytest.mark.parametrize(\'value\',\n    [\n        \'notalist\',\n        42,\n        {},\n    ])\n    def test_list_field_deserialize_value_that_is_not_a_list(self, value):\n        field = fields.List(fields.Str())\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(value)\n        assert excinfo.value.args[0] == \'Not a valid list.\'\n\n    def test_constant_field_deserialization(self):\n        field = fields.Constant(\'something\')\n        assert field.deserialize(\'whatever\') == \'something\'\n\n    def test_constant_is_always_included_in_deserialized_data(self):\n\n        class MySchema(Schema):\n            foo = fields.Constant(42)\n\n        sch = MySchema()\n        assert sch.load({\'bar\': 24}).data[\'foo\'] == 42\n        assert sch.load({\'foo\': 24}).data[\'foo\'] == 42\n\n    def test_field_deserialization_with_user_validator_function(self):\n        field = fields.String(validate=lambda s: s.lower() == \'valid\')\n        assert field.deserialize(\'Valid\') == \'Valid\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'invalid\')\n        assert excinfo.value.args[0][0] == \'Invalid value.\'\n        assert type(excinfo.value) == ValidationError\n\n    def test_field_deserialization_with_user_validator_class_that_returns_bool(self):\n        class MyValidator(object):\n            def __call__(self, val):\n                if val == \'valid\':\n                    return True\n                return False\n\n        field = fields.Field(validate=MyValidator())\n        assert field.deserialize(\'valid\') == \'valid\'\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'invalid\')\n        assert \'Invalid value.\' in str(excinfo)\n\n    def test_field_deserialization_with_user_validator_that_raises_error_with_list(self):\n        def validator(val):\n            raise ValidationError([\'err1\', \'err2\'])\n\n        class MySchema(Schema):\n            foo = fields.Field(validate=validator)\n\n        errors = MySchema().validate({\'foo\': 42})\n        assert errors[\'foo\'] == [\'err1\', \'err2\']\n\n    def test_validator_must_return_false_to_raise_error(self):\n        # validator returns None, so anything validates\n        field = fields.String(validate=lambda s: None)\n        assert field.deserialize(\'Valid\') == \'Valid\'\n        # validator returns False, so nothing validates\n        field2 = fields.String(validate=lambda s: False)\n        with pytest.raises(ValidationError):\n            field2.deserialize(\'invalid\')\n\n    def test_field_deserialization_with_validator_with_nonascii_input(self):\n        field = fields.String(validate=lambda s: False)\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(u\'привет\')\n        assert type(excinfo.value) == ValidationError\n\n    def test_field_deserialization_with_user_validators(self):\n        validators_gen = (func for func in (lambda s: s.lower() == \'valid\',\n                                            lambda s: s.lower()[::-1] == \'dilav\'))\n\n        m_colletion_type = [\n            fields.String(validate=[lambda s: s.lower() == \'valid\',\n                lambda s: s.lower()[::-1] == \'dilav\']),\n            fields.String(validate=(lambda s: s.lower() == \'valid\',\n                lambda s: s.lower()[::-1] == \'dilav\')),\n            fields.String(validate=validators_gen)\n        ]\n\n        for field in m_colletion_type:\n            assert field.deserialize(\'Valid\') == \'Valid\'\n            with pytest.raises(ValidationError) as excinfo:\n                field.deserialize(\'invalid\')\n            assert \'Invalid value.\' in str(excinfo)\n\n    def test_field_deserialization_with_custom_error_message(self):\n        field = fields.String(validate=lambda s: s.lower() == \'valid\',\n                error_messages={\'validator_failed\': \'Bad value.\'})\n        with pytest.raises(ValidationError) as excinfo:\n            field.deserialize(\'invalid\')\n        assert \'Bad value.\' in str(excinfo)\n\n# No custom deserialization behavior, so a dict is returned\nclass SimpleUserSchema(Schema):\n    name = fields.String()\n    age = fields.Float()\n\nclass Validator(Schema):\n    email = fields.Email()\n    colors = fields.Str(validate=validate.OneOf([\'red\', \'blue\']))\n    age = fields.Integer(validate=lambda n: n > 0)\n\nclass Validators(Schema):\n    email = fields.Email()\n    colors = fields.Str(validate=validate.OneOf([\'red\', \'blue\']))\n    age = fields.Integer(validate=[lambda n: n > 0, lambda n: n < 100])\n\nclass TestSchemaDeserialization:\n\n    def test_deserialize_to_dict(self):\n        user_dict = {\'name\': \'Monty\', \'age\': \'42.3\'}\n        result, errors = SimpleUserSchema().load(user_dict)\n        assert result[\'name\'] == \'Monty\'\n        assert_almost_equal(result[\'age\'], 42.3)\n\n    def test_deserialize_with_missing_values(self):\n        user_dict = {\'name\': \'Monty\'}\n        result, errs = SimpleUserSchema().load(user_dict)\n        # \'age\' is not included in result\n        assert result == {\'name\': \'Monty\'}\n\n    def test_deserialize_many(self):\n        users_data = [\n            {\'name\': \'Mick\', \'age\': \'914\'},\n            {\'name\': \'Keith\', \'age\': \'8442\'}\n        ]\n        result, errors = SimpleUserSchema(many=True).load(users_data)\n        assert isinstance(result, list)\n        user = result[0]\n        assert user[\'age\'] == int(users_data[0][\'age\'])\n\n    def test_exclude(self):\n        schema = SimpleUserSchema(exclude=(\'age\', ))\n        result = schema.load({\'name\': \'Monty\', \'age\': 42})\n        assert \'name\' in result.data\n        assert \'age\' not in result.data\n\n    def test_nested_single_deserialization_to_dict(self):\n        class SimpleBlogSerializer(Schema):\n            title = fields.String()\n            author = fields.Nested(SimpleUserSchema)\n\n        blog_dict = {\n            \'title\': \'Gimme Shelter\',\n            \'author\': {\'name\': \'Mick\', \'age\': \'914\', \'email\': \'mick@stones.com\'}\n        }\n        result, errors = SimpleBlogSerializer().load(blog_dict)\n        author = result[\'author\']\n        assert author[\'name\'] == \'Mick\'\n        assert author[\'age\'] == 914\n        assert \'email\' not in author\n\n    def test_nested_list_deserialization_to_dict(self):\n        class SimpleBlogSerializer(Schema):\n            title = fields.String()\n            authors = fields.Nested(SimpleUserSchema, many=True)\n\n        blog_dict = {\n            \'title\': \'Gimme Shelter\',\n            \'authors\': [\n                {\'name\': \'Mick\', \'age\': \'914\'},\n                {\'name\': \'Keith\', \'age\': \'8442\'}\n            ]\n        }\n        result, errors = SimpleBlogSerializer().load(blog_dict)\n        assert isinstance(result[\'authors\'], list)\n        author = result[\'authors\'][0]\n        assert author[\'name\'] == \'Mick\'\n        assert author[\'age\'] == 914\n\n    def test_nested_single_none_not_allowed(self):\n        class PetSchema(Schema):\n            name = fields.Str()\n\n        class OwnerSchema(Schema):\n            pet = fields.Nested(PetSchema(), allow_none=False)\n\n        sch = OwnerSchema()\n        errors = sch.validate({\'pet\': None})\n        assert \'pet\' in errors\n        assert errors[\'pet\'] == [\'Field may not be null.\']\n\n    def test_nested_many_non_not_allowed(self):\n        class PetSchema(Schema):\n            name = fields.Str()\n\n        class StoreSchema(Schema):\n            pets = fields.Nested(PetSchema(), allow_none=False, many=True)\n\n        sch = StoreSchema()\n        errors = sch.validate({\'pets\': None})\n        assert \'pets\' in errors\n        assert errors[\'pets\'] == [\'Field may not be null.\']\n\n    def test_nested_single_required_missing(self):\n        class PetSchema(Schema):\n            name = fields.Str()\n\n        class OwnerSchema(Schema):\n            pet = fields.Nested(PetSchema(), required=True)\n\n        sch = OwnerSchema()\n        errors = sch.validate({})\n        assert \'pet\' in errors\n        assert errors[\'pet\'] == [\'Missing data for required field.\']\n\n    def test_nested_many_required_missing(self):\n        class PetSchema(Schema):\n            name = fields.Str()\n\n        class StoreSchema(Schema):\n            pets = fields.Nested(PetSchema(), required=True, many=True)\n\n        sch = StoreSchema()\n        errors = sch.validate({})\n        assert \'pets\' in errors\n        assert errors[\'pets\'] == [\'Missing data for required field.\']\n\n    def test_none_deserialization(self):\n        result, errors = SimpleUserSchema().load(None)\n        assert result is None\n\n    def test_nested_none_deserialization(self):\n        class SimpleBlogSerializer(Schema):\n            title = fields.String()\n            author = fields.Nested(SimpleUserSchema, allow_none=True)\n\n        blog_dict = {\n            \'title\': \'Gimme Shelter\',\n            \'author\': None\n        }\n        result, errors = SimpleBlogSerializer().load(blog_dict)\n        assert not errors\n        assert result[\'author\'] is None\n        assert result[\'title\'] == blog_dict[\'title\']\n\n    def test_deserialize_with_attribute_param(self):\n        class AliasingUserSerializer(Schema):\n            username = fields.Email(attribute=\'email\')\n            years = fields.Integer(attribute=\'age\')\n        data = {\n            \'username\': \'foo@bar.com\',\n            \'years\': \'42\'\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert result[\'email\'] == \'foo@bar.com\'\n        assert result[\'age\'] == 42\n\n    def test_deserialize_with_attribute_param_error_returns_field_name_not_attribute_name(self):\n        class AliasingUserSerializer(Schema):\n            username = fields.Email(attribute=\'email\')\n            years = fields.Integer(attribute=\'age\')\n        data = {\n            \'username\': \'foobar.com\',\n            \'years\': \'42\'\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert errors\n        assert errors[\'username\'] == [\'Not a valid email address.\']\n\n    def test_deserialize_with_attribute_param_error_returns_load_from_not_attribute_name(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String(load_from=\'Name\')\n            username = fields.Email(attribute=\'email\', load_from=\'UserName\')\n            years = fields.Integer(attribute=\'age\', load_from=\'Years\')\n        data = {\n            \'Name\': \'Mick\',\n            \'UserName\': \'foobar.com\',\n            \'years\': \'abc\'\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert errors[\'UserName\'] == [u\'Not a valid email address.\']\n        assert errors[\'years\'] == [u\'Not a valid integer.\']\n\n    def test_deserialize_with_load_from_param(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String(load_from=\'Name\')\n            username = fields.Email(attribute=\'email\', load_from=\'UserName\')\n            years = fields.Integer(attribute=\'age\', load_from=\'Years\')\n        data = {\n            \'Name\': \'Mick\',\n            \'UserName\': \'foo@bar.com\',\n            \'years\': \'42\'\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert result[\'name\'] == \'Mick\'\n        assert result[\'email\'] == \'foo@bar.com\'\n        assert result[\'age\'] == 42\n\n    def test_deserialize_with_dump_only_param(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String()\n            years = fields.Integer(dump_only=True)\n            nicknames = fields.List(fields.Str(), dump_only=True)\n        data = {\n            \'name\': \'Mick\',\n            \'years\': \'42\',\n            \'nicknames\': [\'Your Majesty\', \'Brenda\']\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert result[\'name\'] == \'Mick\'\n        assert \'years\' not in result\n        assert \'nicknames\' not in result\n\n    def test_deserialize_with_missing_param_value(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String()\n            years = fields.Integer(missing=10)\n        data = {\n            \'name\': \'Mick\',\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert result[\'name\'] == \'Mick\'\n        assert result[\'years\'] == 10\n\n    def test_deserialize_with_missing_param_callable(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String()\n            years = fields.Integer(missing=lambda: 13 + 7)\n        data = {\n            \'name\': \'Mick\',\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert result[\'name\'] == \'Mick\'\n        assert result[\'years\'] == 20\n\n    def test_deserialize_with_missing_param_none(self):\n        class AliasingUserSerializer(Schema):\n            name = fields.String()\n            years = fields.Integer(missing=None, allow_none=True)\n        data = {\n            \'name\': \'Mick\',\n        }\n        result, errors = AliasingUserSerializer().load(data)\n        assert not errors\n        assert result[\'name\'] == \'Mick\'\n        assert result[\'years\'] is None\n\n    def test_deserialization_returns_errors(self):\n        bad_data = {\n            \'email\': \'invalid-email\',\n            \'colors\': \'burger\',\n            \'age\': -1,\n        }\n        v = Validator(strict=False)\n        result, errors = v.load(bad_data)\n        assert \'email\' in errors\n        assert \'colors\' in errors\n        assert \'age\' in errors\n\n    def test_deserialization_returns_errors_with_multiple_validators(self):\n        bad_data = {\n            \'email\': \'invalid-email\',\n            \'colors\': \'burger\',\n            \'age\': -1,\n        }\n        v = Validators(strict=False)\n        result, errors = v.load(bad_data)\n        assert \'email\' in errors\n        assert \'colors\' in errors\n        assert \'age\' in errors\n\n    def test_strict_mode_deserialization(self):\n        bad_data = {\n            \'email\': \'invalid-email\',\n            \'colors\': \'burger\',\n            \'age\': -1,\n        }\n        v = Validator(strict=True)\n        with pytest.raises(ValidationError):\n            v.load(bad_data)\n\n    def test_strict_mode_many(self):\n        bad_data = [\n            {\'email\': \'foo@bar.com\', \'colors\': \'red\', \'age\': 18},\n            {\'email\': \'bad\', \'colors\': \'pizza\', \'age\': -1}\n        ]\n        v = Validator(strict=True, many=True)\n        with pytest.raises(ValidationError):\n            v.load(bad_data)\n\n    def test_strict_mode_deserialization_with_multiple_validators(self):\n        bad_data = {\n            \'email\': \'invalid-email\',\n            \'colors\': \'burger\',\n            \'age\': -1,\n        }\n        v = Validators(strict=True)\n        with pytest.raises(ValidationError):\n            v.load(bad_data)\n\n    def test_uncaught_validation_errors_are_stored(self):\n        def validate_field(val):\n            raise ValidationError(\'Something went wrong\')\n\n        class MySchema(Schema):\n            foo = fields.Field(validate=validate_field)\n\n        _, errors = MySchema().load({\'foo\': 42})\n        assert \'Something went wrong\' in errors[\'foo\']\n\n    def test_multiple_errors_can_be_stored_for_a_field(self):\n\n        def validate_with_bool(n):\n            return False\n\n        def validate_with_error(n):\n            raise ValidationError(\'foo is not valid\')\n\n        class MySchema(Schema):\n            foo = fields.Field(required=True, validate=[\n                validate_with_bool,\n                validate_with_error,\n            ])\n        _, errors = MySchema().load({\'foo\': \'bar\'})\n\n        assert type(errors[\'foo\']) == list\n        assert len(errors[\'foo\']) == 2\n\n    def test_multiple_errors_can_be_stored_for_an_email_field(self):\n        def validate_with_bool(val):\n            return False\n\n        class MySchema(Schema):\n            email = fields.Email(validate=[\n                validate_with_bool,\n            ])\n        _, errors = MySchema().load({\'email\': \'foo\'})\n        assert len(errors[\'email\']) == 2\n        assert \'Not a valid email address.\' in errors[\'email\'][0]\n\n    def test_multiple_errors_can_be_stored_for_a_url_field(self):\n        def validate_with_bool(val):\n            return False\n\n        class MySchema(Schema):\n            url = fields.Url(validate=[\n                validate_with_bool,\n            ])\n        _, errors = MySchema().load({\'url\': \'foo\'})\n        assert len(errors[\'url\']) == 2\n        assert \'Not a valid URL.\' in errors[\'url\'][0]\n\n    def test_required_value_only_passed_to_validators_if_provided(self):\n        class MySchema(Schema):\n            foo = fields.Field(required=True, validate=lambda f: False)\n\n        _, errors = MySchema().load({})\n        # required value missing\n        assert len(errors[\'foo\']) == 1\n        assert \'Missing data for required field.\' in errors[\'foo\']\n\nvalidators_gen = (func for func in [lambda x: x <= 24, lambda x: 18 <= x])\n\nvalidators_gen_float = (func for func in\n                         [lambda f: f <= 4.1, lambda f: f >= 1.0])\n\nvalidators_gen_str = (func for func in\n                        [lambda n: len(n) == 3, lambda n: n[1].lower() == \'o\'])\n\nclass TestValidation:\n\n    def test_integer_with_validator(self):\n        field = fields.Integer(validate=lambda x: 18 <= x <= 24)\n        out = field.deserialize(\'20\')\n        assert out == 20\n        with pytest.raises(ValidationError):\n            field.deserialize(25)\n\n    @pytest.mark.parametrize(\'field\', [\n        fields.Integer(validate=[lambda x: x <= 24, lambda x: 18 <= x]),\n        fields.Integer(validate=(lambda x: x <= 24, lambda x: 18 <= x, )),\n        fields.Integer(validate=validators_gen)\n    ])\n    def test_integer_with_validators(self, field):\n        out = field.deserialize(\'20\')\n        assert out == 20\n        with pytest.raises(ValidationError):\n            field.deserialize(25)\n\n    @pytest.mark.parametrize(\'field\', [\n        fields.Float(validate=[lambda f: f <= 4.1, lambda f: f >= 1.0]),\n        fields.Float(validate=(lambda f: f <= 4.1, lambda f: f >= 1.0, )),\n        fields.Float(validate=validators_gen_float)\n    ])\n    def test_float_with_validators(self, field):\n        assert field.deserialize(3.14)\n        with pytest.raises(ValidationError):\n            field.deserialize(4.2)\n\n    def test_string_validator(self):\n        field = fields.String(validate=lambda n: len(n) == 3)\n        assert field.deserialize(\'Joe\') == \'Joe\'\n        with pytest.raises(ValidationError):\n            field.deserialize(\'joseph\')\n\n    def test_function_validator(self):\n        field = fields.Function(lambda d: d.name.upper(),\n                                validate=lambda n: len(n) == 3)\n        assert field.deserialize(\'joe\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'joseph\')\n\n    @pytest.mark.parametrize(\'field\', [\n        fields.Function(lambda d: d.name.upper(),\n            validate=[lambda n: len(n) == 3, lambda n: n[1].lower() == \'o\']),\n        fields.Function(lambda d: d.name.upper(),\n            validate=(lambda n: len(n) == 3, lambda n: n[1].lower() == \'o\')),\n        fields.Function(lambda d: d.name.upper(),\n            validate=validators_gen_str)\n    ])\n    def test_function_validators(self, field):\n        assert field.deserialize(\'joe\')\n        with pytest.raises(ValidationError):\n            field.deserialize(\'joseph\')\n\n    def test_method_validator(self):\n        class MethodSerializer(Schema):\n            name = fields.Method(\'get_name\', deserialize=\'get_name\',\n                                      validate=lambda n: len(n) == 3)\n\n            def get_name(self, val):\n                return val.upper()\n        assert MethodSerializer(strict=True).load({\'name\': \'joe\'})\n        with pytest.raises(ValidationError) as excinfo:\n            MethodSerializer(strict=True).load({\'name\': \'joseph\'})\n\n        assert \'Invalid value.\' in str(excinfo)\n\n    # Regression test for https://github.com/marshmallow-code/marshmallow/issues/269\n    def test_nested_data_is_stored_when_validation_fails(self):\n        class SchemaA(Schema):\n            x = fields.Integer()\n            y = fields.Integer(validate=lambda n: n > 0)\n            z = fields.Integer()\n\n        class SchemaB(Schema):\n            w = fields.Integer()\n            n = fields.Nested(SchemaA)\n\n        sch = SchemaB()\n\n        data, errors = sch.load({\'w\': 90, \'n\': {\'x\': 90, \'y\': 89, \'z\': None}})\n        assert \'z\' in errors[\'n\']\n        assert data == {\'w\': 90, \'n\': {\'x\': 90, \'y\': 89}}\n\n        data, errors = sch.load({\'w\': 90, \'n\': {\'x\': 90, \'y\': -1, \'z\': 180}})\n        assert \'y\' in errors[\'n\']\n        assert data == {\'w\': 90, \'n\': {\'x\': 90, \'z\': 180}}\n\n\nFIELDS_TO_TEST = [f for f in ALL_FIELDS if f not in [fields.FormattedString]]\n@pytest.mark.parametrize(\'FieldClass\', FIELDS_TO_TEST)\ndef test_required_field_failure(FieldClass):  # noqa\n    class RequireSchema(Schema):\n        age = FieldClass(required=True)\n    user_data = {"name": "Phil"}\n    data, errs = RequireSchema().load(user_data)\n    assert "Missing data for required field." in errs[\'age\']\n    assert data == {}\n\n@pytest.mark.parametrize(\'message\', [\'My custom required message\',\n                                     {\'error\': \'something\', \'code\': 400},\n                                     [\'first error\', \'second error\']])\ndef test_required_message_can_be_changed(message):\n    class RequireSchema(Schema):\n        age = fields.Integer(required=message)\n\n    user_data = {"name": "Phil"}\n    data, errs = RequireSchema().load(user_data)\n    expected = [message] if isinstance(message, basestring) else message\n    assert expected == errs[\'age\']\n    assert data == {}\n\n# Regression test for https://github.com/marshmallow-code/marshmallow/issues/261\ndef test_deserialize_doesnt_raise_exception_if_strict_is_false_and_input_type_is_incorrect():\n    class MySchema(Schema):\n        foo = fields.Field()\n        bar = fields.Field()\n    data, errs = MySchema().load([])\n    assert \'_schema\' in errs\n    assert errs[\'_schema\'] == [\'Invalid input type.\']\n\n\ndef test_deserialize_raises_exception_if_strict_is_true_and_input_type_is_incorrect():\n    class MySchema(Schema):\n        foo = fields.Field()\n        bar = fields.Field()\n    with pytest.raises(ValidationError) as excinfo:\n        MySchema(strict=True).load([])\n    assert \'Invalid input type.\' in str(excinfo)\n    exc = excinfo.value\n    assert exc.field_names == [\'_schema\']\n    assert exc.fields == []\n',
        }
